{
  "name": "PopCross: Infinite Culture Puzzles",
  "description": "A modern, neon-styled daily crossword game focused on TV, Movies, and Music. Powered by Gemini to generate fresh puzzles on demand."
}

export type Direction = 'across' | 'down';

export interface Clue {
  number: number;
  direction: Direction;
  text: string;
  answer: string;
  row: number;
  col: number;
}

export interface CellData {
  row: number;
  col: number;
  value: string; // The correct letter
  userValue: string; // The user's input
  isBlack: boolean;
  number: number | null; // The clue number if this is the start of a word
  active: boolean; // Is currently selected
  related: boolean; // Is part of the active word
  isCorrect: boolean;
}

export interface PuzzleData {
  title: string;
  theme: string;
  gridSize: number;
  grid: string[][]; // The solution grid
  clues: Clue[];
}

export interface GameState {
  status: 'idle' | 'generating' | 'playing' | 'completed';
  puzzle: PuzzleData | null;
  grid: CellData[][];
  selectedCell: { row: number; col: number } | null;
  direction: Direction;
  timer: number;
  hintsUsed: number;
}

export type Topic = 'Movies' | 'TV Shows' | 'Music' | '90s Pop Culture' | 'Modern Hits';

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PuzzleData, Clue } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const PUZZLE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "A witty title for the puzzle" },
    rows: {
      type: Type.ARRAY,
      description: "5 strings, each exactly 5 letters long, representing the rows of the grid. All uppercase.",
      items: { type: Type.STRING }
    },
    acrossClues: {
      type: Type.ARRAY,
      description: "5 clues corresponding to the 5 rows.",
      items: { type: Type.STRING }
    },
    downClues: {
      type: Type.ARRAY,
      description: "5 clues corresponding to the 5 columns formed by the rows.",
      items: { type: Type.STRING }
    }
  },
  required: ["title", "rows", "acrossClues", "downClues"]
};

export const generatePuzzle = async (topic: string): Promise<PuzzleData> => {
  const modelId = "gemini-3-flash-preview";

  const prompt = `
    Create a dense 5x5 mini-crossword puzzle about: ${topic}.

    Rules:
    1. The grid must be 5x5.
    2. Every square must be filled with a letter (no black squares).
    3. The words formed Across (rows) and Down (columns) must be real words or proper nouns related to pop culture, TV, Movies, or Music if possible.
    4. Provide witty, fun, or trivia-based clues.
    5. Ensure the letters in the 'rows' create valid vertical words for the 'down' clues.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: PUZZLE_SCHEMA,
        systemInstruction: "You are a professional crossword constructor specializing in pop culture trivia.",
        thinkingConfig: { thinkingBudget: 0 } // Speed over deep reasoning for minis
      }
    });

    const json = JSON.parse(response.text || "{}");

    if (!json.rows || json.rows.length !== 5) {
      throw new Error("Invalid puzzle generated");
    }

    // Convert flat JSON to our Game Structure
    const grid: string[][] = json.rows.map((row: string) => row.toUpperCase().split('').slice(0, 5));
    const clues: Clue[] = [];

    // Process Across Clues
    json.acrossClues.forEach((text: string, index: number) => {
      clues.push({
        number: index + 1,
        direction: 'across',
        text: text,
        answer: grid[index].join(''),
        row: index,
        col: 0
      });
    });

    // Process Down Clues
    // For a dense 5x5 without black squares, down clues start at the top row (indices 1-5 usually, but let's number them logically)
    // In standard crosswords, numbers are assigned sequentially. 
    // For this mini format, let's keep it simple: Row 1 = 1 Across, Col 1 = 1 Down.
    // Actually, distinct numbers are better. 
    // Top row cells: (0,0) is #1, (0,1) is #2, etc.
    // BUT for simplicity in this specific "Dense Mini" UI:
    // We will list 1-5 Across and 1-5 Down (like NYT Mini often does visually for simple grids, though strictly they share numbers).
    // Let's implement standard numbering logic in the UI, but here we just map the data.

    // Construct vertical words to verify
    const verticalWords: string[] = [];
    for (let c = 0; c < 5; c++) {
      let word = "";
      for (let r = 0; r < 5; r++) {
        word += grid[r][c];
      }
      verticalWords.push(word);
    }

    json.downClues.forEach((text: string, index: number) => {
      clues.push({
        number: index + 1, // Visual simplification for Mini: 1A, 2A... and 1D, 2D...
        direction: 'down',
        text: text,
        answer: verticalWords[index],
        row: 0,
        col: index
      });
    });

    return {
      title: json.title,
      theme: topic,
      gridSize: 5,
      grid,
      clues
    };

  } catch (error) {
    console.error("Failed to generate puzzle:", error);
    throw error;
  }
};

export const getHintForCell = async (clue: string, currentAnswerPattern: string): Promise<string> => {
    // A simplified hint generator
    const prompt = `The crossword clue is "${clue}". The answer pattern is "${currentAnswerPattern}" (where _ is unknown). Give me a very short, subtle hint without revealing the word.`;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
    });
    return response.text || "Try thinking about synonyms.";
}

import React from 'react';
import { Delete } from 'lucide-react';

interface VirtualKeyboardProps {
  onKeyPress: (key: string) => void;
  onDelete: () => void;
  onEnter?: () => void;
}

const KEYS = [
  ['Q', 'W', 'E', 'R', 'T', 'Y', 'U', 'I', 'O', 'P'],
  ['A', 'S', 'D', 'F', 'G', 'H', 'J', 'K', 'L'],
  ['Z', 'X', 'C', 'V', 'B', 'N', 'M']
];

export const VirtualKeyboard: React.FC<VirtualKeyboardProps> = ({ onKeyPress, onDelete }) => {
  return (
    <div className="w-full max-w-2xl mx-auto p-2 pb-6 select-none">
      <div className="flex flex-col gap-2">
        {KEYS.map((row, rowIndex) => (
          <div key={rowIndex} className="flex justify-center gap-1.5">
            {row.map((key) => (
              <button
                key={key}
                onClick={() => onKeyPress(key)}
                className="w-8 h-10 sm:w-10 sm:h-12 bg-slate-700 hover:bg-slate-600 active:bg-slate-500 text-white font-bold rounded shadow-md transition-colors text-sm sm:text-base"
              >
                {key}
              </button>
            ))}
            {rowIndex === 2 && (
              <button
                onClick={onDelete}
                className="w-12 h-10 sm:w-14 sm:h-12 bg-slate-800 hover:bg-red-900/50 text-white rounded shadow-md flex items-center justify-center transition-colors ml-1"
              >
                <Delete size={20} />
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

import React from 'react';
import { CellData } from '../types';

interface PuzzleGridProps {
  grid: CellData[][];
  onCellClick: (row: number, col: number) => void;
}

export const PuzzleGrid: React.FC<PuzzleGridProps> = ({ grid, onCellClick }) => {
  return (
    <div 
      className="grid gap-1 bg-slate-900 p-2 rounded-lg shadow-2xl border-2 border-slate-700 mx-auto"
      style={{
        gridTemplateColumns: `repeat(${grid.length}, minmax(0, 1fr))`,
        maxWidth: '350px' // Keep it compact for Mini feel
      }}
    >
      {grid.map((row, rIndex) => (
        row.map((cell, cIndex) => (
          <div
            key={`${rIndex}-${cIndex}`}
            onClick={() => onCellClick(rIndex, cIndex)}
            className={`
              relative aspect-square flex items-center justify-center text-xl font-bold uppercase cursor-pointer select-none transition-all duration-150
              ${cell.active ? 'bg-fuchsia-600 text-white ring-2 ring-fuchsia-300 z-10' : 
                cell.related ? 'bg-fuchsia-900/40 text-fuchsia-100' : 
                'bg-slate-800 text-white hover:bg-slate-700'}
              ${cell.isCorrect && !cell.active ? 'text-green-400' : ''}
              rounded-md
            `}
          >
            {/* Number Label */}
            {cell.number && (
              <span className="absolute top-0.5 left-1 text-[10px] font-normal opacity-70 leading-none">
                {cell.number}
              </span>
            )}

            {/* Value */}
            <span className="mt-1">{cell.userValue}</span>
          </div>
        ))
      ))}
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameState, CellData, Direction, Topic, PuzzleData } from './types';
import { generatePuzzle, getHintForCell } from './services/geminiService';
import { PuzzleGrid } from './components/PuzzleGrid';
import { VirtualKeyboard } from './components/VirtualKeyboard';
import { Clapperboard, Music, Tv, Loader2, Sparkles, Trophy, HelpCircle, Share2, Play } from 'lucide-react';

const TOPICS: { id: Topic; icon: React.ReactNode; label: string }[] = [
  { id: 'Movies', icon: <Clapperboard size={18} />, label: 'Movies' },
  { id: 'TV Shows', icon: <Tv size={18} />, label: 'TV' },
  { id: 'Music', icon: <Music size={18} />, label: 'Music' },
  { id: '90s Pop Culture', icon: <Sparkles size={18} />, label: '90s' },
];

export default function App() {
  const [gameState, setGameState] = useState<GameState>({
    status: 'idle',
    puzzle: null,
    grid: [],
    selectedCell: null,
    direction: 'across',
    timer: 0,
    hintsUsed: 0
  });

  const [aiHint, setAiHint] = useState<string | null>(null);
  const [isAiThinking, setIsAiThinking] = useState(false);

  // Initialize Timer
  useEffect(() => {
    let interval: number;
    if (gameState.status === 'playing') {
      interval = window.setInterval(() => {
        setGameState(prev => ({ ...prev, timer: prev.timer + 1 }));
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [gameState.status]);

  const startNewGame = async (topic: Topic) => {
    setGameState(prev => ({ ...prev, status: 'generating', hintsUsed: 0, timer: 0 }));
    setAiHint(null);
    try {
      const puzzle = await generatePuzzle(topic);

      // Initialize Grid
      const newGrid: CellData[][] = puzzle.grid.map((row, r) => 
        row.map((char, c) => ({
          row: r,
          col: c,
          value: char,
          userValue: '',
          isBlack: false,
          number: (r === 0 || c === 0) ? null : null, // Numbering logic handled below
          active: false,
          related: false,
          isCorrect: false
        }))
      );

      // Apply numbers based on clues (Simplified for 5x5 dense: Top row gets 1-5, Left Col gets 1-5 implicitly)
      // Visual numbering: 1-5 top row
      puzzle.clues.filter(c => c.direction === 'down').forEach(clue => {
         if (newGrid[clue.row][clue.col]) {
             newGrid[clue.row][clue.col].number = clue.number;
         }
      });
      // Ensure across numbers overwrite or coexist? For 5x5 dense, 1D is usually at 0,0. 1A is also at 0,0.
      // We will just show the number if it exists in any clue starting there.
      puzzle.clues.forEach(clue => {
          newGrid[clue.row][clue.col].number = clue.number;
      });

      setGameState({
        status: 'playing',
        puzzle,
        grid: newGrid,
        selectedCell: { row: 0, col: 0 },
        direction: 'across',
        timer: 0,
        hintsUsed: 0
      });

      updateSelectionHighlights(newGrid, { row: 0, col: 0 }, 'across');

    } catch (error) {
      console.error(error);
      setGameState(prev => ({ ...prev, status: 'idle' }));
      alert("Failed to generate puzzle. Please check your API key or try again.");
    }
  };

  const updateSelectionHighlights = (
    currentGrid: CellData[][], 
    selected: { row: number, col: number } | null, 
    dir: Direction
  ) => {
    if (!selected) return;

    const newGrid = currentGrid.map(row => row.map(cell => ({ ...cell, active: false, related: false })));

    // Set active cell
    newGrid[selected.row][selected.col].active = true;

    // Highlight related word
    if (dir === 'across') {
      newGrid[selected.row].forEach(cell => cell.related = true);
    } else {
      newGrid.forEach(row => {
        if (row[selected.col]) row[selected.col].related = true;
      });
    }

    setGameState(prev => ({ ...prev, grid: newGrid, selectedCell: selected, direction: dir }));
  };

  const handleCellClick = (row: number, col: number) => {
    if (gameState.status !== 'playing') return;

    if (gameState.selectedCell?.row === row && gameState.selectedCell?.col === col) {
      // Toggle direction
      const newDir = gameState.direction === 'across' ? 'down' : 'across';
      updateSelectionHighlights(gameState.grid, { row, col }, newDir);
    } else {
      updateSelectionHighlights(gameState.grid, { row, col }, gameState.direction);
    }
  };

  const checkWinCondition = (grid: CellData[][]) => {
    const allCorrect = grid.every(row => row.every(cell => cell.userValue === cell.value));
    if (allCorrect) {
      setGameState(prev => ({ ...prev, status: 'completed' }));
    }
  };

  const handleInput = useCallback((char: string) => {
    if (gameState.status !== 'playing' || !gameState.selectedCell) return;

    const { row, col } = gameState.selectedCell;
    const newGrid = [...gameState.grid];
    newGrid[row][col] = { ...newGrid[row][col], userValue: char, isCorrect: char === newGrid[row][col].value };

    // Move selection
    let nextRow = row;
    let nextCol = col;

    if (gameState.direction === 'across') {
       if (col < 4) nextCol++;
    } else {
       if (row < 4) nextRow++;
    }

    updateSelectionHighlights(newGrid, { row: nextRow, col: nextCol }, gameState.direction);
    checkWinCondition(newGrid);
  }, [gameState]);

  const handleBackspace = useCallback(() => {
    if (gameState.status !== 'playing' || !gameState.selectedCell) return;
    const { row, col } = gameState.selectedCell;
    const newGrid = [...gameState.grid];

    // If current is empty, move back then delete
    if (newGrid[row][col].userValue === '') {
        let prevRow = row;
        let prevCol = col;
        if (gameState.direction === 'across') {
            if (col > 0) prevCol--;
        } else {
            if (row > 0) prevRow--;
        }
        updateSelectionHighlights(newGrid, { row: prevRow, col: prevCol }, gameState.direction);
    } else {
        newGrid[row][col].userValue = '';
        setGameState(prev => ({ ...prev, grid: newGrid }));
    }
  }, [gameState]);

  // Keyboard Event Listener
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (gameState.status !== 'playing') return;
        if (e.key.match(/^[a-zA-Z]$/)) {
            handleInput(e.key.toUpperCase());
        } else if (e.key === 'Backspace') {
            handleBackspace();
        } else if (e.key === 'ArrowUp') {
            const r = Math.max(0, (gameState.selectedCell?.row || 0) - 1);
            updateSelectionHighlights(gameState.grid, {row: r, col: gameState.selectedCell?.col || 0}, gameState.direction);
        } else if (e.key === 'ArrowDown') {
            const r = Math.min(4, (gameState.selectedCell?.row || 0) + 1);
            updateSelectionHighlights(gameState.grid, {row: r, col: gameState.selectedCell?.col || 0}, gameState.direction);
        } else if (e.key === 'ArrowLeft') {
            const c = Math.max(0, (gameState.selectedCell?.col || 0) - 1);
            updateSelectionHighlights(gameState.grid, {row: gameState.selectedCell?.row || 0, col: c}, gameState.direction);
        } else if (e.key === 'ArrowRight') {
            const c = Math.min(4, (gameState.selectedCell?.col || 0) + 1);
            updateSelectionHighlights(gameState.grid, {row: gameState.selectedCell?.row || 0, col: c}, gameState.direction);
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [gameState, handleInput, handleBackspace]);


  const getCurrentClue = () => {
    if (!gameState.puzzle || !gameState.selectedCell) return null;
    const { row, col } = gameState.selectedCell;

    // Find clue matching current cell and direction
    // For 5x5 dense:
    // Across clue is simply the row index + 1 (if we mapped them that way)
    // Down clue is simply the col index + 1
    // We stored the clues with row/col data in generatePuzzle, so let's find it.

    const clue = gameState.puzzle.clues.find(c => {
      if (gameState.direction === 'across') return c.row === row && c.direction === 'across';
      if (gameState.direction === 'down') return c.col === col && c.direction === 'down';
      return false;
    });

    return clue;
  };

  const handleAskAI = async () => {
      const clue = getCurrentClue();
      if (!clue || isAiThinking) return;

      setIsAiThinking(true);
      // Construct partial answer for context e.g. "A _ _ L E"
      let pattern = "";
      if (gameState.direction === 'across') {
          pattern = gameState.grid[clue.row].map(c => c.userValue || "_").join(" ");
      } else {
          gameState.grid.forEach(r => {
             pattern += (r[clue.col].userValue || "_") + " ";
          });
      }

      try {
          const hint = await getHintForCell(clue.text, pattern);
          setAiHint(hint);
          setGameState(prev => ({ ...prev, hintsUsed: prev.hintsUsed + 1 }));
      } catch (e) {
          setAiHint("Could not fetch hint. Try again.");
      } finally {
          setIsAiThinking(false);
      }
  };

  const currentClue = getCurrentClue();

  // ---------------- RENDER ----------------

  if (gameState.status === 'idle') {
    return (
      <div className="min-h-screen bg-slate-950 text-white flex flex-col items-center justify-center p-6 relative overflow-hidden">
        {/* Decorative Background Elements */}
        <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
            <div className="absolute top-1/4 left-1/4 w-64 h-64 bg-fuchsia-600 rounded-full blur-[100px]" />
            <div className="absolute bottom-1/4 right-1/4 w-64 h-64 bg-cyan-600 rounded-full blur-[100px]" />
        </div>

        <div className="z-10 text-center max-w-md w-full">
          <h1 className="text-5xl md:text-6xl font-black mb-2 tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-fuchsia-400 to-cyan-400 drop-shadow-[0_0_15px_rgba(232,121,249,0.3)]">
            POPCROSS
          </h1>
          <p className="text-slate-400 text-lg mb-8 font-medium">Infinite Culture Puzzles</p>

          <div className="bg-slate-900/50 backdrop-blur-md border border-slate-800 rounded-2xl p-6 shadow-2xl">
            <h2 className="text-xl font-bold mb-4 text-slate-200">Pick a Vibe</h2>
            <div className="grid grid-cols-2 gap-3">
              {TOPICS.map(topic => (
                <button
                  key={topic.id}
                  onClick={() => startNewGame(topic.id)}
                  className="flex flex-col items-center justify-center gap-2 p-4 bg-slate-800 hover:bg-slate-700 active:bg-slate-600 border border-slate-700 hover:border-fuchsia-500/50 rounded-xl transition-all duration-200 group"
                >
                  <div className="text-cyan-400 group-hover:text-fuchsia-400 transition-colors duration-200">
                    {topic.icon}
                  </div>
                  <span className="font-semibold text-sm">{topic.label}</span>
                </button>
              ))}
            </div>
          </div>
          <p className="mt-8 text-xs text-slate-600 uppercase tracking-widest">Powered by Gemini AI</p>
        </div>
      </div>
    );
  }

  if (gameState.status === 'generating') {
    return (
      <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center text-white">
        <Loader2 size={48} className="animate-spin text-fuchsia-500 mb-4" />
        <h2 className="text-2xl font-bold animate-pulse">Constructing Puzzle...</h2>
        <p className="text-slate-400 mt-2">Consulting the pop culture archives</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-950 text-white flex flex-col">
      {/* Header */}
      <header className="px-4 py-3 bg-slate-900/80 backdrop-blur border-b border-slate-800 flex justify-between items-center sticky top-0 z-20">
        <div className="flex items-center gap-2" onClick={() => setGameState(p => ({...p, status: 'idle'}))}>
            <div className="w-8 h-8 bg-gradient-to-br from-fuchsia-500 to-cyan-500 rounded-md flex items-center justify-center font-bold text-xs cursor-pointer">
                PC
            </div>
            <div className="hidden sm:block font-bold text-lg">{gameState.puzzle?.theme} Mini</div>
        </div>
        <div className="flex items-center gap-4 text-sm font-mono text-slate-400">
            <span>{Math.floor(gameState.timer / 60)}:{(gameState.timer % 60).toString().padStart(2, '0')}</span>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-lg mx-auto w-full p-4 flex flex-col gap-6">

        {/* Clue Bar */}
        <div className="bg-slate-800/80 p-4 rounded-xl border-l-4 border-fuchsia-500 min-h-[5rem] flex flex-col justify-center shadow-lg relative overflow-hidden transition-all">
          <div className="flex justify-between items-start mb-1">
             <span className="text-xs font-bold uppercase text-fuchsia-400 tracking-wider">
               {gameState.direction.toUpperCase()}
             </span>
             {isAiThinking && <Loader2 size={16} className="animate-spin text-cyan-400"/>}
          </div>
          <p className="text-lg font-medium leading-tight text-slate-100">
            {currentClue ? `${currentClue.number}. ${currentClue.text}` : 'Select a cell'}
          </p>

          {/* AI Hint Overlay */}
          {aiHint && (
             <div className="absolute inset-0 bg-slate-800/95 backdrop-blur-sm p-4 flex items-center justify-between animate-in fade-in slide-in-from-bottom-2">
                 <p className="text-sm text-cyan-300 italic">"{aiHint}"</p>
                 <button onClick={() => setAiHint(null)} className="text-xs bg-slate-700 px-2 py-1 rounded ml-2">Close</button>
             </div>
          )}
        </div>

        {/* Grid */}
        <div className="flex-1 flex flex-col items-center justify-center min-h-[300px]">
            {gameState.status === 'completed' ? (
                <div className="text-center animate-in zoom-in duration-500">
                    <Trophy size={64} className="mx-auto text-yellow-400 mb-4 drop-shadow-glow" />
                    <h2 className="text-3xl font-black text-white mb-2">PUZZLE SOLVED!</h2>
                    <p className="text-slate-400 mb-6">Time: {Math.floor(gameState.timer / 60)}m {gameState.timer % 60}s</p>
                    <div className="flex gap-3 justify-center">
                        <button onClick={() => setGameState(prev => ({...prev, status: 'idle'}))} className="bg-fuchsia-600 hover:bg-fuchsia-500 text-white px-6 py-3 rounded-full font-bold flex items-center gap-2">
                            <Play size={18} /> Play Another
                        </button>
                        <button className="bg-slate-700 hover:bg-slate-600 px-6 py-3 rounded-full font-bold flex items-center gap-2">
                            <Share2 size={18} /> Share
                        </button>
                    </div>
                </div>
            ) : (
                <PuzzleGrid 
                    grid={gameState.grid} 
                    onCellClick={handleCellClick}
                />
            )}
        </div>

        {/* Controls */}
        {gameState.status === 'playing' && (
            <div className="flex justify-between items-center px-4">
                 <button 
                   onClick={handleAskAI}
                   disabled={isAiThinking}
                   className="flex items-center gap-2 text-cyan-400 text-sm font-semibold hover:text-cyan-300 disabled:opacity-50"
                 >
                    <Sparkles size={16} /> 
                    Ask AI Hint
                 </button>
                 <div className="text-xs text-slate-500">{gameState.hintsUsed} hints used</div>
            </div>
        )}

        {/* Keyboard */}
        {gameState.status === 'playing' && (
            <VirtualKeyboard 
                onKeyPress={handleInput} 
                onDelete={handleBackspace} 
            />
        )}
      </main>
    </div>
  );
}

