export type Direction = 'across' | 'down';

export interface Clue {
  number: number;
  direction: Direction;
  text: string;
  answer: string;
  row: number;
  col: number;
}

export interface CellData {
  row: number;
  col: number;
  value: string; // The correct letter
  userValue: string; // The user's input
  isBlack: boolean;
  number: number | null; // The clue number if this is the start of a word
  active: boolean; // Is currently selected
  related: boolean; // Is part of the active word
  isCorrect: boolean;
  isRevealed: boolean; // Was this revealed by a tool?
}

export interface PuzzleData {
  title: string;
  theme: string;
  gridSize: number;
  grid: string[][]; // The solution grid
  clues: Clue[];
}

export type Difficulty = 'Easy' | 'Medium' | 'Hard' | 'Very Hard';
export type Region = 'Global' | 'USA' | 'UK';

export interface GameSettings {
  difficulty: Difficulty;
  region: Region;
}

export interface UserStats {
  totalPoints: number;
  gamesPlayed: number;
  gamesWon: number;
  currentStreak: number;
  maxStreak: number;
  lastDailyDate: string | null; // ISO date string
}

export interface GameState {
  status: 'idle' | 'generating' | 'playing' | 'completed';
  puzzle: PuzzleData | null;
  grid: CellData[][];
  selectedCell: { row: number; col: number } | null;
  direction: Direction;
  timer: number;
  hintsUsed: number;
  revealsUsed: number;
  score: number;
  isDaily: boolean;
  settings: GameSettings;
}

export type Topic = 'Movies' | 'TV Shows' | 'Music' | '90s Pop Culture' | 'Modern Hits' | 'Sci-Fi' | 'Reality TV' | 'Superheroes' | 'Classic Rock';

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PuzzleData, Clue, Difficulty, Region } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const PUZZLE_SCHEMA: Schema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING, description: "A witty title for the puzzle" },
    rows: {
      type: Type.ARRAY,
      description: "5 strings, each exactly 5 letters long, representing the rows of the grid. All uppercase.",
      items: { type: Type.STRING }
    },
    acrossClues: {
      type: Type.ARRAY,
      description: "5 clues corresponding to the 5 rows.",
      items: { type: Type.STRING }
    },
    downClues: {
      type: Type.ARRAY,
      description: "5 clues corresponding to the 5 columns formed by the rows.",
      items: { type: Type.STRING }
    }
  },
  required: ["title", "rows", "acrossClues", "downClues"]
};

const getDifficultyPrompt = (diff: Difficulty): string => {
  switch (diff) {
    case 'Easy': return "Use very common words and direct, simple clues suitable for beginners.";
    case 'Medium': return "Use standard pop culture terms with a mix of direct and slightly clever clues.";
    case 'Hard': return "Use niche trivia, some obscure names, and witty, pun-based clues.";
    case 'Very Hard': return "Use obscure deep-cuts, difficult wordplay, and very challenging trivia. Avoid common words.";
    default: return "";
  }
};

const getRegionPrompt = (region: Region): string => {
  switch (region) {
    case 'UK': return "Prioritize British TV, British Music, and UK spelling/slang.";
    case 'USA': return "Focus primarily on Hollywood and American charts.";
    case 'Global': return "Ensure the references are globally recognized blockbusters and hits.";
    default: return "";
  }
};

export const generatePuzzle = async (topic: string, difficulty: Difficulty, region: Region): Promise<PuzzleData> => {
  const modelId = "gemini-3-flash-preview";

  const prompt = `
    Create a dense 5x5 mini-crossword puzzle about: ${topic}.

    Configuration:
    - Difficulty: ${difficulty}. ${getDifficultyPrompt(difficulty)}
    - Region Context: ${region}. ${getRegionPrompt(region)}

    Rules:
    1. The grid must be 5x5.
    2. Every square must be filled with a letter (no black squares).
    3. The words formed Across (rows) and Down (columns) must be real words or proper nouns related to the topic.
    4. Ensure the letters in the 'rows' create valid vertical words for the 'down' clues.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: PUZZLE_SCHEMA,
        systemInstruction: "You are a professional crossword constructor specializing in pop culture trivia.",
        thinkingConfig: { thinkingBudget: 0 } 
      }
    });

    const json = JSON.parse(response.text || "{}");

    if (!json.rows || json.rows.length !== 5) {
      throw new Error("Invalid puzzle generated");
    }

    const grid: string[][] = json.rows.map((row: string) => row.toUpperCase().split('').slice(0, 5));
    const clues: Clue[] = [];

    // Process Across Clues
    json.acrossClues.forEach((text: string, index: number) => {
      clues.push({
        number: index + 1,
        direction: 'across',
        text: text,
        answer: grid[index].join(''),
        row: index,
        col: 0
      });
    });

    // Construct vertical words
    const verticalWords: string[] = [];
    for (let c = 0; c < 5; c++) {
      let word = "";
      for (let r = 0; r < 5; r++) {
        word += grid[r][c];
      }
      verticalWords.push(word);
    }

    json.downClues.forEach((text: string, index: number) => {
      clues.push({
        number: index + 1,
        direction: 'down',
        text: text,
        answer: verticalWords[index],
        row: 0,
        col: index
      });
    });

    return {
      title: json.title,
      theme: topic,
      gridSize: 5,
      grid,
      clues
    };

  } catch (error) {
    console.error("Failed to generate puzzle:", error);
    throw error;
  }
};

export const getHintForCell = async (clue: string, currentAnswerPattern: string): Promise<string> => {
    const prompt = `The crossword clue is "${clue}". The answer pattern is "${currentAnswerPattern}" (where _ is unknown). Give me a very short, subtle hint without revealing the word.`;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
    });
    return response.text || "Try thinking about synonyms.";
}

import React, { useState, useEffect, useCallback } from 'react';
import { GameState, CellData, Direction, Topic, PuzzleData, GameSettings, UserStats } from './types';
import { generatePuzzle, getHintForCell } from './services/geminiService';
import { PuzzleGrid } from './components/PuzzleGrid';
import { VirtualKeyboard } from './components/VirtualKeyboard';
import { 
  Clapperboard, Music, Tv, Loader2, Sparkles, Trophy, 
  Share2, Play, Zap, Calendar, Globe, Gauge, 
  Eye, Type, AlertCircle, Save 
} from 'lucide-react';

const TOPICS: { id: Topic; icon: React.ReactNode; label: string }[] = [
  { id: 'Movies', icon: <Clapperboard size={16} />, label: 'Movies' },
  { id: 'TV Shows', icon: <Tv size={16} />, label: 'TV' },
  { id: 'Music', icon: <Music size={16} />, label: 'Music' },
  { id: '90s Pop Culture', icon: <Sparkles size={16} />, label: '90s' },
  { id: 'Modern Hits', icon: <Zap size={16} />, label: 'Modern' },
  { id: 'Sci-Fi', icon: <Globe size={16} />, label: 'Sci-Fi' },
  { id: 'Reality TV', icon: <Eye size={16} />, label: 'Reality' },
  { id: 'Superheroes', icon: <Zap size={16} />, label: 'Heroes' },
  { id: 'Classic Rock', icon: <Music size={16} />, label: 'Rock' },
];

const INITIAL_STATS: UserStats = {
  totalPoints: 0,
  gamesPlayed: 0,
  gamesWon: 0,
  currentStreak: 0,
  maxStreak: 0,
  lastDailyDate: null,
};

const BASE_WIN_POINTS = 1000;
const HINT_PENALTY = 50;
const REVEAL_LETTER_PENALTY = 100;
const REVEAL_WORD_PENALTY = 200;

export default function App() {
  const [stats, setStats] = useState<UserStats>(INITIAL_STATS);
  const [gameState, setGameState] = useState<GameState>({
    status: 'idle',
    puzzle: null,
    grid: [],
    selectedCell: null,
    direction: 'across',
    timer: 0,
    hintsUsed: 0,
    revealsUsed: 0,
    score: 0,
    isDaily: false,
    settings: {
      difficulty: 'Medium',
      region: 'Global'
    }
  });

  const [aiHint, setAiHint] = useState<string | null>(null);
  const [isAiThinking, setIsAiThinking] = useState(false);
  const [savedGameExists, setSavedGameExists] = useState(false);

  // Load Persistence
  useEffect(() => {
    const savedStats = localStorage.getItem('popcross_stats_v1');
    if (savedStats) setStats(JSON.parse(savedStats));

    const savedGame = localStorage.getItem('popcross_save_v1');
    if (savedGame) setSavedGameExists(true);
  }, []);

  // Save Stats
  useEffect(() => {
    localStorage.setItem('popcross_stats_v1', JSON.stringify(stats));
  }, [stats]);

  // Save Game Progress
  useEffect(() => {
    if (gameState.status === 'playing') {
      localStorage.setItem('popcross_save_v1', JSON.stringify(gameState));
    } else if (gameState.status === 'completed' || gameState.status === 'idle') {
      // Don't clear immediately on idle to allow "Resume" feature logic
      if (gameState.status === 'completed') {
        localStorage.removeItem('popcross_save_v1');
        setSavedGameExists(false);
      }
    }
  }, [gameState]);

  // Timer
  useEffect(() => {
    let interval: number;
    if (gameState.status === 'playing') {
      interval = window.setInterval(() => {
        setGameState(prev => ({ ...prev, timer: prev.timer + 1 }));
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [gameState.status]);

  const resumeGame = () => {
    const saved = localStorage.getItem('popcross_save_v1');
    if (saved) {
      setGameState(JSON.parse(saved));
    }
  };

  const startNewGame = async (topic: string, isDaily: boolean = false) => {
    setGameState(prev => ({ 
      ...prev, 
      status: 'generating', 
      hintsUsed: 0, 
      revealsUsed: 0, 
      timer: 0,
      score: 0,
      isDaily
    }));
    setAiHint(null);

    try {
      // For daily, force a specific config or just random mix
      const theme = isDaily ? "Daily Mix" : topic;
      const puzzle = await generatePuzzle(theme, gameState.settings.difficulty, gameState.settings.region);

      const newGrid: CellData[][] = puzzle.grid.map((row, r) => 
        row.map((char, c) => ({
          row: r,
          col: c,
          value: char,
          userValue: '',
          isBlack: false,
          number: null,
          active: false,
          related: false,
          isCorrect: false,
          isRevealed: false
        }))
      );

      // Numbering
      puzzle.clues.forEach(clue => {
         if (newGrid[clue.row][clue.col]) {
             newGrid[clue.row][clue.col].number = clue.number;
         }
      });

      const newState: GameState = {
        ...gameState,
        status: 'playing',
        puzzle,
        grid: newGrid,
        selectedCell: { row: 0, col: 0 },
        direction: 'across',
        timer: 0,
        hintsUsed: 0,
        revealsUsed: 0,
        score: 0,
        isDaily,
        // Keep existing settings
      };

      setGameState(newState);
      updateSelectionHighlights(newGrid, { row: 0, col: 0 }, 'across', newState);

    } catch (error) {
      console.error(error);
      setGameState(prev => ({ ...prev, status: 'idle' }));
      alert("Failed to generate puzzle. Please check your API key or try again.");
    }
  };

  const updateSelectionHighlights = (
    currentGrid: CellData[][], 
    selected: { row: number, col: number } | null, 
    dir: Direction,
    stateOverride?: GameState
  ) => {
    if (!selected) return;

    const newGrid = currentGrid.map(row => row.map(cell => ({ ...cell, active: false, related: false })));
    newGrid[selected.row][selected.col].active = true;

    if (dir === 'across') {
      newGrid[selected.row].forEach(cell => cell.related = true);
    } else {
      newGrid.forEach(row => {
        if (row[selected.col]) row[selected.col].related = true;
      });
    }

    setGameState(prev => ({ 
        ...(stateOverride || prev), 
        grid: newGrid, 
        selectedCell: selected, 
        direction: dir 
    }));
  };

  const handleCellClick = (row: number, col: number) => {
    if (gameState.status !== 'playing') return;
    if (gameState.selectedCell?.row === row && gameState.selectedCell?.col === col) {
      const newDir = gameState.direction === 'across' ? 'down' : 'across';
      updateSelectionHighlights(gameState.grid, { row, col }, newDir);
    } else {
      updateSelectionHighlights(gameState.grid, { row, col }, gameState.direction);
    }
  };

  const calculateScore = (time: number, hints: number, reveals: number) => {
    // Time bonus: Starts at 500, decreases by 2 per second, min 0
    const timeBonus = Math.max(0, 500 - (time * 2));
    const penalties = (hints * HINT_PENALTY) + reveals; // reveals already weighted in state tracking? No, let's track count
    return Math.max(0, BASE_WIN_POINTS + timeBonus - penalties);
  };

  const checkWinCondition = (grid: CellData[][]) => {
    const allCorrect = grid.every(row => row.every(cell => cell.userValue === cell.value));
    if (allCorrect) {
      // Calculate Final Score
      // For simplicity, revealsUsed in state is just a count. We need to weight them.
      // Actually, let's just calculate current penalty based on counters.
      // We need to differentiate letter vs word reveal in state to be precise, 
      // but simpler: maintain a `scoreDeduction` in state.

      const timeBonus = Math.max(0, 500 - (gameState.timer * 2));
      const finalScore = Math.max(0, BASE_WIN_POINTS + timeBonus - gameState.score); // gameState.score holds penalties

      setGameState(prev => ({ ...prev, status: 'completed', score: finalScore }));

      // Update Stats
      const today = new Date().toISOString().split('T')[0];
      setStats(prev => {
        const isNewDay = prev.lastDailyDate !== today;
        let newStreak = prev.currentStreak;

        if (gameState.isDaily && isNewDay) {
           newStreak += 1;
        }

        return {
          totalPoints: prev.totalPoints + finalScore,
          gamesPlayed: prev.gamesPlayed + 1,
          gamesWon: prev.gamesWon + 1,
          currentStreak: newStreak,
          maxStreak: Math.max(prev.maxStreak, newStreak),
          lastDailyDate: gameState.isDaily ? today : prev.lastDailyDate
        };
      });
    }
  };

  const handleInput = useCallback((char: string) => {
    if (gameState.status !== 'playing' || !gameState.selectedCell) return;
    const { row, col } = gameState.selectedCell;

    // Don't overwrite correct/revealed cells
    if (gameState.grid[row][col].isRevealed) return;

    const newGrid = [...gameState.grid];
    newGrid[row][col] = { 
        ...newGrid[row][col], 
        userValue: char, 
        isCorrect: char === newGrid[row][col].value 
    };

    let nextRow = row;
    let nextCol = col;
    if (gameState.direction === 'across') {
       if (col < 4) nextCol++;
    } else {
       if (row < 4) nextRow++;
    }

    updateSelectionHighlights(newGrid, { row: nextRow, col: nextCol }, gameState.direction);
    checkWinCondition(newGrid);
  }, [gameState]);

  const handleBackspace = useCallback(() => {
    if (gameState.status !== 'playing' || !gameState.selectedCell) return;
    const { row, col } = gameState.selectedCell;
    const newGrid = [...gameState.grid];

    if (newGrid[row][col].isRevealed) return;

    if (newGrid[row][col].userValue === '') {
        let prevRow = row;
        let prevCol = col;
        if (gameState.direction === 'across') {
            if (col > 0) prevCol--;
        } else {
            if (row > 0) prevRow--;
        }
        updateSelectionHighlights(newGrid, { row: prevRow, col: prevCol }, gameState.direction);
    } else {
        newGrid[row][col].userValue = '';
        setGameState(prev => ({ ...prev, grid: newGrid }));
    }
  }, [gameState]);

  // Keyboard
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (gameState.status !== 'playing') return;
        if (e.key.match(/^[a-zA-Z]$/)) handleInput(e.key.toUpperCase());
        else if (e.key === 'Backspace') handleBackspace();
        else if (e.key === 'ArrowUp') {
            const r = Math.max(0, (gameState.selectedCell?.row || 0) - 1);
            updateSelectionHighlights(gameState.grid, {row: r, col: gameState.selectedCell?.col || 0}, gameState.direction);
        } else if (e.key === 'ArrowDown') {
            const r = Math.min(4, (gameState.selectedCell?.row || 0) + 1);
            updateSelectionHighlights(gameState.grid, {row: r, col: gameState.selectedCell?.col || 0}, gameState.direction);
        } else if (e.key === 'ArrowLeft') {
            const c = Math.max(0, (gameState.selectedCell?.col || 0) - 1);
            updateSelectionHighlights(gameState.grid, {row: gameState.selectedCell?.row || 0, col: c}, gameState.direction);
        } else if (e.key === 'ArrowRight') {
            const c = Math.min(4, (gameState.selectedCell?.col || 0) + 1);
            updateSelectionHighlights(gameState.grid, {row: gameState.selectedCell?.row || 0, col: c}, gameState.direction);
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [gameState, handleInput, handleBackspace]);


  const getCurrentClue = () => {
    if (!gameState.puzzle || !gameState.selectedCell) return null;
    const { row, col } = gameState.selectedCell;
    return gameState.puzzle.clues.find(c => {
      if (gameState.direction === 'across') return c.row === row && c.direction === 'across';
      if (gameState.direction === 'down') return c.col === col && c.direction === 'down';
      return false;
    });
  };

  const handleAskAI = async () => {
      const clue = getCurrentClue();
      if (!clue || isAiThinking) return;
      setIsAiThinking(true);
      let pattern = "";
      if (gameState.direction === 'across') {
          pattern = gameState.grid[clue.row].map(c => c.userValue || "_").join(" ");
      } else {
          gameState.grid.forEach(r => { pattern += (r[clue.col].userValue || "_") + " "; });
      }
      try {
          const hint = await getHintForCell(clue.text, pattern);
          setAiHint(hint);
          setGameState(prev => ({ 
              ...prev, 
              hintsUsed: prev.hintsUsed + 1,
              score: prev.score + HINT_PENALTY 
          }));
      } catch (e) {
          setAiHint("Could not fetch hint.");
      } finally {
          setIsAiThinking(false);
      }
  };

  const handleRevealLetter = () => {
      if (!gameState.selectedCell) return;
      const { row, col } = gameState.selectedCell;
      if (gameState.grid[row][col].userValue === gameState.grid[row][col].value) return;

      const newGrid = [...gameState.grid];
      newGrid[row][col] = {
          ...newGrid[row][col],
          userValue: newGrid[row][col].value,
          isCorrect: true,
          isRevealed: true
      };

      setGameState(prev => ({
          ...prev,
          grid: newGrid,
          score: prev.score + REVEAL_LETTER_PENALTY
      }));
      checkWinCondition(newGrid);
  };

  const handleRevealWord = () => {
      if (!gameState.selectedCell) return;
      const { row, col } = gameState.selectedCell;
      const newGrid = [...gameState.grid];

      if (gameState.direction === 'across') {
          newGrid[row].forEach(cell => {
              cell.userValue = cell.value;
              cell.isCorrect = true;
              cell.isRevealed = true;
          });
      } else {
          newGrid.forEach(r => {
              r[col].userValue = r[col].value;
              r[col].isCorrect = true;
              r[col].isRevealed = true;
          });
      }

      setGameState(prev => ({
          ...prev,
          grid: newGrid,
          score: prev.score + REVEAL_WORD_PENALTY
      }));
      checkWinCondition(newGrid);
  };

  const currentClue = getCurrentClue();
  const isDailyDone = stats.lastDailyDate === new Date().toISOString().split('T')[0];

  // ---------------- RENDER ----------------

  if (gameState.status === 'idle') {
    return (
      <div className="min-h-screen bg-slate-950 text-white flex flex-col items-center p-6 relative overflow-y-auto">
        <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none fixed">
            <div className="absolute top-1/4 left-1/4 w-64 h-64 bg-fuchsia-600 rounded-full blur-[100px]" />
            <div className="absolute bottom-1/4 right-1/4 w-64 h-64 bg-cyan-600 rounded-full blur-[100px]" />
        </div>

        <div className="z-10 text-center max-w-lg w-full mt-8">
          <h1 className="text-5xl md:text-6xl font-black mb-1 tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-fuchsia-400 to-cyan-400 drop-shadow-[0_0_15px_rgba(232,121,249,0.3)]">
            POPCROSS
          </h1>
          <p className="text-slate-400 text-lg mb-8 font-medium">Infinite Culture Puzzles</p>

          {/* Stats Bar */}
          <div className="flex justify-center gap-6 mb-8 bg-slate-900/50 p-4 rounded-xl border border-slate-800">
             <div className="text-center">
                 <div className="flex items-center justify-center gap-1 text-yellow-400 font-bold text-xl">
                     <Zap size={20} fill="currentColor" /> {stats.currentStreak}
                 </div>
                 <div className="text-[10px] uppercase text-slate-500 tracking-wider">Streak</div>
             </div>
             <div className="text-center border-l border-slate-700 pl-6">
                 <div className="flex items-center justify-center gap-1 text-cyan-400 font-bold text-xl">
                     <Trophy size={20} /> {stats.totalPoints.toLocaleString()}
                 </div>
                 <div className="text-[10px] uppercase text-slate-500 tracking-wider">Score</div>
             </div>
          </div>

          <div className="space-y-4 mb-8">
             {/* Controls */}
             <div className="flex gap-2">
                 <div className="flex-1">
                     <label className="text-xs text-slate-500 uppercase mb-1 block">Difficulty</label>
                     <div className="flex bg-slate-800 rounded-lg p-1">
                         {['Easy', 'Medium', 'Hard', 'Very Hard'].map((d) => (
                             <button 
                                key={d}
                                onClick={() => setGameState(p => ({...p, settings: {...p.settings, difficulty: d as any}}))}
                                className={`flex-1 py-2 text-[10px] sm:text-xs rounded-md transition-all ${gameState.settings.difficulty === d ? 'bg-fuchsia-600 text-white font-bold' : 'text-slate-400 hover:bg-slate-700'}`}
                             >
                                 {d === 'Very Hard' ? 'X-Hard' : d}
                             </button>
                         ))}
                     </div>
                 </div>
             </div>
             <div>
                <label className="text-xs text-slate-500 uppercase mb-1 block">Region</label>
                <div className="flex bg-slate-800 rounded-lg p-1">
                        {['Global', 'USA', 'UK'].map((r) => (
                            <button 
                            key={r}
                            onClick={() => setGameState(p => ({...p, settings: {...p.settings, region: r as any}}))}
                            className={`flex-1 py-2 text-xs rounded-md transition-all ${gameState.settings.region === r ? 'bg-cyan-600 text-white font-bold' : 'text-slate-400 hover:bg-slate-700'}`}
                            >
                                {r}
                            </button>
                        ))}
                    </div>
             </div>
          </div>

          {/* Main Actions */}
          <div className="grid gap-3 mb-8">
              {savedGameExists && (
                  <button 
                    onClick={resumeGame}
                    className="w-full py-4 bg-slate-800 border border-fuchsia-500/30 text-fuchsia-300 rounded-xl font-bold flex items-center justify-center gap-2 hover:bg-slate-800/80"
                  >
                      <Save size={20} /> Resume Saved Puzzle
                  </button>
              )}

              <button 
                onClick={() => startNewGame("Daily Challenge", true)}
                disabled={isDailyDone}
                className={`w-full py-4 rounded-xl font-bold flex items-center justify-center gap-2 border transition-all
