import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PuzzleData, Clue, Difficulty, Region } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const getGridSize = (difficulty: Difficulty): number => {
  switch (difficulty) {
    case 'Easy': return 4;      // 4x4 = 8 words
    case 'Medium': return 5;    // 5x5 = 10 words
    case 'Hard': return 6;      // 6x6 = 12 words
    case 'Very Hard': return 7; // 7x7 = 14 words
    default: return 5;
  }
};

const getPuzzleSchema = (size: number): Schema => {
  return {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING, description: "A witty title for the puzzle" },
      rows: {
        type: Type.ARRAY,
        description: `${size} strings, each exactly ${size} letters long, representing the rows of the grid. All uppercase.`,
        items: { type: Type.STRING }
      },
      acrossClues: {
        type: Type.ARRAY,
        description: `${size} clues corresponding to the ${size} rows.`,
        items: { type: Type.STRING }
      },
      downClues: {
        type: Type.ARRAY,
        description: `${size} clues corresponding to the ${size} columns formed by the rows.`,
        items: { type: Type.STRING }
      }
    },
    required: ["title", "rows", "acrossClues", "downClues"]
  };
};

const getDifficultyPrompt = (diff: Difficulty): string => {
  switch (diff) {
    case 'Easy': return "Use very common words and direct, simple clues.";
    case 'Medium': return "Use standard pop culture terms.";
    case 'Hard': return "Use niche trivia and clever clues.";
    case 'Very Hard': return "Use obscure deep-cuts and difficult wordplay.";
    default: return "";
  }
};

const getRegionPrompt = (region: Region): string => {
  switch (region) {
    case 'UK': return "Prioritize British TV, British Music, and UK spelling/slang.";
    case 'USA': return "Focus primarily on Hollywood and American charts.";
    case 'Global': return "Ensure the references are globally recognized blockbusters and hits.";
    default: return "";
  }
};

export const generatePuzzle = async (topic: string, difficulty: Difficulty, region: Region): Promise<PuzzleData> => {
  const modelId = "gemini-3-flash-preview";
  const size = getGridSize(difficulty);
  const schema = getPuzzleSchema(size);

  const prompt = `
    Create a dense ${size}x${size} mini-crossword puzzle about: ${topic}.

    Configuration:
    - Grid Size: ${size}x${size} (${size * 2} words total).
    - Difficulty: ${difficulty}. ${getDifficultyPrompt(difficulty)}
    - Region Context: ${region}. ${getRegionPrompt(region)}

    Rules:
    1. The grid must be exactly ${size}x${size}.
    2. Every square must be filled with a letter (NO black squares allowed).
    3. The words formed Across (rows) and Down (columns) must be real words or proper nouns related to the topic if possible.
    4. Ensure the letters in the 'rows' create valid vertical words for the 'down' clues.
    5. Return exactly ${size} rows, ${size} across clues, and ${size} down clues.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
        systemInstruction: "You are a professional crossword constructor. You must create valid dense grids without black squares.",
        thinkingConfig: { thinkingBudget: 0 } 
      }
    });

    const json = JSON.parse(response.text || "{}");

    if (!json.rows || json.rows.length !== size) {
      throw new Error("Invalid puzzle generated");
    }

    const grid: string[][] = json.rows.map((row: string) => row.toUpperCase().split('').slice(0, size));
    const clues: Clue[] = [];

    // Process Across Clues
    json.acrossClues.forEach((text: string, index: number) => {
      clues.push({
        number: index + 1,
        direction: 'across',
        text: text,
        answer: grid[index].join(''),
        row: index,
        col: 0
      });
    });

    // Construct vertical words
    const verticalWords: string[] = [];
    for (let c = 0; c < size; c++) {
      let word = "";
      for (let r = 0; r < size; r++) {
        word += grid[r][c];
      }
      verticalWords.push(word);
    }

    json.downClues.forEach((text: string, index: number) => {
      clues.push({
        number: index + 1,
        direction: 'down',
        text: text,
        answer: verticalWords[index],
        row: 0,
        col: index
      });
    });

    return {
      title: json.title,
      theme: topic,
      gridSize: size,
      grid,
      clues
    };

  } catch (error) {
    console.error("Failed to generate puzzle:", error);
    throw error;
  }
};

export const getHintForCell = async (clue: string, currentAnswerPattern: string): Promise<string> => {
    const prompt = `The crossword clue is "${clue}". The answer pattern is "${currentAnswerPattern}" (where _ is unknown). Give me a very short, subtle hint without revealing the word.`;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
    });
    return response.text || "Try thinking about synonyms.";
}

