];

const INITIAL_STATS: UserStats = {
  totalPoints: 0,
  gamesPlayed: 0,
  gamesWon: 0,
  currentStreak: 0,
  maxStreak: 0,
  lastDailyDate: null,
};

const BASE_WIN_POINTS = 1000;
const HINT_PENALTY = 50;
const REVEAL_LETTER_PENALTY = 100;
const REVEAL_WORD_PENALTY = 200;

export default function App() {
  const [stats, setStats] = useState<UserStats>(INITIAL_STATS);
  const [gameState, setGameState] = useState<GameState>({
    status: 'idle',
    puzzle: null,
    grid: [],
    selectedCell: null,
    direction: 'across',
    timer: 0,
    hintsUsed: 0,
    revealsUsed: 0,
    score: 0,
    isDaily: false,
    settings: {
      difficulty: 'Medium',
      region: 'Global'
    }
  });

  const [aiHint, setAiHint] = useState<string | null>(null);
  const [isAiThinking, setIsAiThinking] = useState(false);
  const [savedGameExists, setSavedGameExists] = useState(false);

  // Load Persistence
  useEffect(() => {
    const savedStats = localStorage.getItem('popcross_stats_v1');
    if (savedStats) setStats(JSON.parse(savedStats));

    const savedGame = localStorage.getItem('popcross_save_v1');
    if (savedGame) setSavedGameExists(true);
  }, []);

  // Save Stats
  useEffect(() => {
    localStorage.setItem('popcross_stats_v1', JSON.stringify(stats));
  }, [stats]);

  // Save Game Progress
  useEffect(() => {
    if (gameState.status === 'playing') {
      localStorage.setItem('popcross_save_v1', JSON.stringify(gameState));
    } else if (gameState.status === 'completed' || gameState.status === 'idle') {
      if (gameState.status === 'completed') {
        localStorage.removeItem('popcross_save_v1');
        setSavedGameExists(false);
      }
    }
  }, [gameState]);

  // Timer
  useEffect(() => {
    let interval: number;
    if (gameState.status === 'playing') {
      interval = window.setInterval(() => {
        setGameState(prev => ({ ...prev, timer: prev.timer + 1 }));
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [gameState.status]);

  const resumeGame = () => {
    const saved = localStorage.getItem('popcross_save_v1');
    if (saved) {
      setGameState(JSON.parse(saved));
    }
  };

  const startNewGame = async (topic: string, isDaily: boolean = false) => {
    setGameState(prev => ({ 
      ...prev, 
      status: 'generating', 
      hintsUsed: 0, 
      revealsUsed: 0, 
      timer: 0,
      score: 0,
      isDaily
    }));
    setAiHint(null);

    try {
      const theme = isDaily ? "Daily Mix" : topic;
      const puzzle = await generatePuzzle(theme, gameState.settings.difficulty, gameState.settings.region);

      const newGrid: CellData[][] = puzzle.grid.map((row, r) => 
        row.map((char, c) => ({
          row: r,
          col: c,
          value: char,
          userValue: '',
          isBlack: false,
          number: null,
          active: false,
          related: false,
          isCorrect: false,
          isRevealed: false
        }))
      );

      puzzle.clues.forEach(clue => {
         if (newGrid[clue.row][clue.col]) {
             newGrid[clue.row][clue.col].number = clue.number;
         }
      });

      const newState: GameState = {
        ...gameState,
        status: 'playing',
        puzzle,
        grid: newGrid,
        selectedCell: { row: 0, col: 0 },
        direction: 'across',
        timer: 0,
        hintsUsed: 0,
        revealsUsed: 0,
        score: 0,
        isDaily,
      };

      setGameState(newState);
      updateSelectionHighlights(newGrid, { row: 0, col: 0 }, 'across', newState);

    } catch (error) {
      console.error(error);
      setGameState(prev => ({ ...prev, status: 'idle' }));
      alert("Failed to generate puzzle. Please check your API key or try again.");
    }
  };

  const updateSelectionHighlights = (
    currentGrid: CellData[][], 
    selected: { row: number, col: number } | null, 
    dir: Direction,
    stateOverride?: GameState
  ) => {
    if (!selected) return;

    const newGrid = currentGrid.map(row => row.map(cell => ({ ...cell, active: false, related: false })));
    newGrid[selected.row][selected.col].active = true;

    if (dir === 'across') {
      newGrid[selected.row].forEach(cell => cell.related = true);
    } else {
      newGrid.forEach(row => {
        if (row[selected.col]) row[selected.col].related = true;
      });
    }

    setGameState(prev => ({ 
        ...(stateOverride || prev), 
        grid: newGrid, 
        selectedCell: selected, 
        direction: dir 
    }));
  };

  const handleCellClick = (row: number, col: number) => {
    if (gameState.status !== 'playing') return;
    if (gameState.selectedCell?.row === row && gameState.selectedCell?.col === col) {
      const newDir = gameState.direction === 'across' ? 'down' : 'across';
      updateSelectionHighlights(gameState.grid, { row, col }, newDir);
    } else {
      updateSelectionHighlights(gameState.grid, { row, col }, gameState.direction);
    }
  };

  const checkWinCondition = (grid: CellData[][]) => {
    const allCorrect = grid.every(row => row.every(cell => cell.userValue === cell.value));
    if (allCorrect) {
      const timeBonus = Math.max(0, 500 - (gameState.timer * 2));
      const finalScore = Math.max(0, BASE_WIN_POINTS + timeBonus - gameState.score); 

      setGameState(prev => ({ ...prev, status: 'completed', score: finalScore }));

      const today = new Date().toISOString().split('T')[0];
      setStats(prev => {
        const isNewDay = prev.lastDailyDate !== today;
        let newStreak = prev.currentStreak;
        if (gameState.isDaily && isNewDay) newStreak += 1;

        return {
          totalPoints: prev.totalPoints + finalScore,
          gamesPlayed: prev.gamesPlayed + 1,
          gamesWon: prev.gamesWon + 1,
          currentStreak: newStreak,
          maxStreak: Math.max(prev.maxStreak, newStreak),
          lastDailyDate: gameState.isDaily ? today : prev.lastDailyDate
        };
      });
    }
  };

  const handleInput = useCallback((char: string) => {
    if (gameState.status !== 'playing' || !gameState.selectedCell) return;
    const { row, col } = gameState.selectedCell;

    if (gameState.grid[row][col].isRevealed) return;

    const newGrid = [...gameState.grid];
    newGrid[row][col] = { 
        ...newGrid[row][col], 
        userValue: char, 
        isCorrect: char === newGrid[row][col].value 
    };

    let nextRow = row;
    let nextCol = col;
    if (gameState.direction === 'across') {
       if (col < newGrid.length - 1) nextCol++;
    } else {
       if (row < newGrid.length - 1) nextRow++;
    }

    updateSelectionHighlights(newGrid, { row: nextRow, col: nextCol }, gameState.direction);
    checkWinCondition(newGrid);
  }, [gameState]);

  const handleBackspace = useCallback(() => {
    if (gameState.status !== 'playing' || !gameState.selectedCell) return;
    const { row, col } = gameState.selectedCell;
    const newGrid = [...gameState.grid];

    if (newGrid[row][col].isRevealed) return;

    if (newGrid[row][col].userValue === '') {
        let prevRow = row;
        let prevCol = col;
        if (gameState.direction === 'across') {
            if (col > 0) prevCol--;
        } else {
            if (row > 0) prevRow--;
        }
        updateSelectionHighlights(newGrid, { row: prevRow, col: prevCol }, gameState.direction);
    } else {
        newGrid[row][col].userValue = '';
        setGameState(prev => ({ ...prev, grid: newGrid }));
    }
  }, [gameState]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (gameState.status !== 'playing') return;
        if (e.key.match(/^[a-zA-Z]$/)) handleInput(e.key.toUpperCase());
        else if (e.key === 'Backspace') handleBackspace();
        else if (e.key === 'ArrowUp') {
            const r = Math.max(0, (gameState.selectedCell?.row || 0) - 1);
            updateSelectionHighlights(gameState.grid, {row: r, col: gameState.selectedCell?.col || 0}, gameState.direction);
        } else if (e.key === 'ArrowDown') {
            const r = Math.min(gameState.grid.length - 1, (gameState.selectedCell?.row || 0) + 1);
            updateSelectionHighlights(gameState.grid, {row: r, col: gameState.selectedCell?.col || 0}, gameState.direction);
        } else if (e.key === 'ArrowLeft') {
            const c = Math.max(0, (gameState.selectedCell?.col || 0) - 1);
            updateSelectionHighlights(gameState.grid, {row: gameState.selectedCell?.row || 0, col: c}, gameState.direction);
        } else if (e.key === 'ArrowRight') {
            const c = Math.min(gameState.grid.length - 1, (gameState.selectedCell?.col || 0) + 1);
            updateSelectionHighlights(gameState.grid, {row: gameState.selectedCell?.row || 0, col: c}, gameState.direction);
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [gameState, handleInput, handleBackspace]);


  const getCurrentClue = () => {
    if (!gameState.puzzle || !gameState.selectedCell) return null;
    const { row, col } = gameState.selectedCell;
    return gameState.puzzle.clues.find(c => {
      if (gameState.direction === 'across') return c.row === row && c.direction === 'across';
      if (gameState.direction === 'down') return c.col === col && c.direction === 'down';
      return false;
    });
  };

  const handleAskAI = async () => {
      const clue = getCurrentClue();
      if (!clue || isAiThinking) return;
      setIsAiThinking(true);
      let pattern = "";
      if (gameState.direction === 'across') {
          pattern = gameState.grid[clue.row].map(c => c.userValue || "_").join(" ");
      } else {
          gameState.grid.forEach(r => { pattern += (r[clue.col].userValue || "_") + " "; });
      }
      try {
          const hint = await getHintForCell(clue.text, pattern);
          setAiHint(hint);
          setGameState(prev => ({ 
              ...prev, 
              hintsUsed: prev.hintsUsed + 1,
              score: prev.score + HINT_PENALTY 
          }));
      } catch (e) {
          setAiHint("Could not fetch hint.");
      } finally {
          setIsAiThinking(false);
      }
  };

  const handleRevealLetter = () => {
      if (!gameState.selectedCell) return;
      const { row, col } = gameState.selectedCell;
      if (gameState.grid[row][col].userValue === gameState.grid[row][col].value) return;

      const newGrid = [...gameState.grid];
      newGrid[row][col] = {
          ...newGrid[row][col],
          userValue: newGrid[row][col].value,
          isCorrect: true,
          isRevealed: true
      };

      setGameState(prev => ({
          ...prev,
          grid: newGrid,
          score: prev.score + REVEAL_LETTER_PENALTY
      }));
      checkWinCondition(newGrid);
  };

  const handleRevealWord = () => {
      if (!gameState.selectedCell) return;
      const { row, col } = gameState.selectedCell;
      const newGrid = [...gameState.grid];

      if (gameState.direction === 'across') {
          newGrid[row].forEach(cell => {
              cell.userValue = cell.value;
              cell.isCorrect = true;
              cell.isRevealed = true;
          });
      } else {
          newGrid.forEach(r => {
              r[col].userValue = r[col].value;
              r[col].isCorrect = true;
              r[col].isRevealed = true;
          });
      }

      setGameState(prev => ({
          ...prev,
          grid: newGrid,
          score: prev.score + REVEAL_WORD_PENALTY
      }));
      checkWinCondition(newGrid);
  };

  const currentClue = getCurrentClue();
  const isDailyDone = stats.lastDailyDate === new Date().toISOString().split('T')[0];

  // ---------------- RENDER ----------------

  // Background Element
  const Background = () => (
      <div className="fixed inset-0 pointer-events-none z-[-1]">
          {/* Deep Gradient Background */}
          <div className="absolute inset-0 bg-gradient-to-br from-[#0f0c29] via-[#302b63] to-[#24243e] opacity-90" />

          {/* Animated Glow Blobs */}
          <div className="absolute top-[-10%] left-[-10%] w-[500px] h-[500px] bg-fuchsia-600/20 rounded-full blur-[120px] mix-blend-screen" />
          <div className="absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] bg-cyan-600/20 rounded-full blur-[120px] mix-blend-screen" />
      </div>
  );

  if (gameState.status === 'idle') {
    return (
      <div className="min-h-screen text-white flex flex-col items-center p-6 relative overflow-y-auto">
        <Background />

        <div className="z-10 text-center max-w-lg w-full mt-12 animate-[fade-in_0.6s_ease-out]">
          <h1 className="text-6xl md:text-7xl font-black mb-2 tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-fuchsia-300 via-white to-cyan-300 drop-shadow-[0_0_25px_rgba(217,70,239,0.5)]">
            POPCROSS
          </h1>
          <p className="text-slate-300 text-lg mb-10 font-medium tracking-wide">INFINITE CULTURE PUZZLES</p>

          {/* Stats Bar */}
          <div className="flex justify-center gap-0 mb-10 glass-panel rounded-2xl p-1 shadow-2xl">
             <div className="flex-1 text-center py-3 px-6 border-r border-white/10">
                 <div className="flex items-center justify-center gap-2 text-yellow-400 font-bold text-2xl font-mono text-glow">
                     <Zap size={22} fill="currentColor" /> {stats.currentStreak}
                 </div>
                 <div className="text-[10px] uppercase text-slate-400 font-bold tracking-widest mt-1">Daily Streak</div>
             </div>
             <div className="flex-1 text-center py-3 px-6">
                 <div className="flex items-center justify-center gap-2 text-cyan-400 font-bold text-2xl font-mono text-glow">
                     <Trophy size={22} /> {stats.totalPoints.toLocaleString()}
                 </div>
                 <div className="text-[10px] uppercase text-slate-400 font-bold tracking-widest mt-1">Total Score</div>
             </div>
          </div>

          <div className="space-y-6 mb-10">
             {/* Settings */}
             <div className="glass-panel p-4 rounded-xl space-y-4">
                 <div className="flex flex-col gap-2">
                     <label className="text-[10px] text-slate-400 uppercase font-bold tracking-widest ml-1">Difficulty</label>
                     <div className="flex bg-black/40 rounded-lg p-1 border border-white/5">
                         {['Easy', 'Medium', 'Hard', 'Very Hard'].map((d) => (
                             <button 
                                key={d}
                                onClick={() => setGameState(p => ({...p, settings: {...p.settings, difficulty: d as any}}))}
                                className={`flex-1 py-2 text-[10px] sm:text-xs rounded-md transition-all font-bold ${gameState.settings.difficulty === d ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-900/50' : 'text-slate-500 hover:text-slate-300 hover:bg-white/5'}`}
                             >
                                 {d === 'Very Hard' ? 'X-HARD' : d.toUpperCase()}
                             </button>
                         ))}
                     </div>
                 </div>
                 <div className="flex flex-col gap-2">
                    <label className="text-[10px] text-slate-400 uppercase font-bold tracking-widest ml-1">Region</label>
                    <div className="flex bg-black/40 rounded-lg p-1 border border-white/5">
                        {['Global', 'USA', 'UK'].map((r) => (
                            <button 
                            key={r}
                            onClick={() => setGameState(p => ({...p, settings: {...p.settings, region: r as any}}))}
                            className={`flex-1 py-2 text-xs rounded-md transition-all font-bold ${gameState.settings.region === r ? 'bg-cyan-600 text-white shadow-lg shadow-cyan-900/50' : 'text-slate-500 hover:text-slate-300 hover:bg-white/5'}`}
                            >
                                {r.toUpperCase()}
                            </button>
                        ))}
                    </div>
                 </div>
             </div>
          </div>

          {/* Main Actions */}
          <div className="grid gap-4 mb-10">
              {savedGameExists && (
                  <button 
                    onClick={resumeGame}
                    className="w-full py-4 bg-slate-800/80 border border-fuchsia-500/50 text-fuchsia-300 rounded-xl font-bold flex items-center justify-center gap-3 hover:bg-fuchsia-900/20 hover:shadow-[0_0_20px_rgba(217,70,239,0.2)] transition-all group"
                  >
                      <Save size={20} className="group-hover:scale-110 transition-transform"/> RESUME SESSION
                  </button>
              )}

              <button 
                onClick={() => startNewGame("Daily Challenge", true)}
                disabled={isDailyDone}
                className={`w-full py-5 rounded-xl font-black text-lg tracking-wide flex items-center justify-center gap-3 border transition-all relative overflow-hidden group
                    ${isDailyDone 
                        ? 'bg-slate-900/50 border-slate-800 text-slate-600 cursor-not-allowed' 
                        : 'bg-gradient-to-r from-amber-600/20 to-orange-600/20 border-amber-500/50 text-amber-400 hover:border-amber-400 hover:shadow-[0_0_30px_rgba(245,158,11,0.3)]'
                    }
                `}
              >
                  {!isDailyDone && <div className="absolute inset-0 bg-amber-500/10 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700 blur-md"></div>}
                  <Calendar size={22} className={isDailyDone ? "" : "animate-pulse"}/> 
                  {isDailyDone ? "DAILY CHALLENGE COMPLETED" : "DAILY CHALLENGE"}
              </button>
          </div>

          <h2 className="text-xl font-bold mb-4 text-white/80 text-left border-b border-white/10 pb-2">Quick Play</h2>
          <div className="grid grid-cols-3 gap-3 pb-12">
            {TOPICS.map(topic => (
              <button
                key={topic.id}
                onClick={() => startNewGame(topic.id)}
                className="glass-panel hover:bg-white/10 border-white/5 hover:border-white/20 rounded-xl p-3 flex flex-col items-center justify-center gap-3 h-28 transition-all duration-200 group relative overflow-hidden"
              >
                <div className={`${topic.color} opacity-80 group-hover:opacity-100 group-hover:scale-110 transition-all duration-300 drop-shadow-lg`}>
                  {topic.icon}
                </div>
                <span className="font-bold text-xs text-slate-300 group-hover:text-white uppercase tracking-wider text-center leading-tight">{topic.label}</span>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (gameState.status === 'generating') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center text-white px-4 text-center">
        <Background />
        <div className="glass-panel p-8 rounded-2xl flex flex-col items-center shadow-2xl border border-fuchsia-500/30">
            <Loader2 size={56} className="animate-spin text-fuchsia-400 mb-6 drop-shadow-glow" />
            <h2 className="text-3xl font-bold animate-pulse mb-3 bg-clip-text text-transparent bg-gradient-to-r from-fuchsia-300 to-cyan-300">GENERATING</h2>
            <p className="text-slate-400 text-sm font-mono mb-4">Consulting the Archives...</p>
            <div className="flex gap-2 text-[10px] uppercase font-bold tracking-widest text-slate-500">
                <span className="px-3 py-1 bg-black/40 rounded border border-white/10">{gameState.settings.difficulty}</span>
                <span className="px-3 py-1 bg-black/40 rounded border border-white/10">{gameState.settings.region}</span>
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen text-white flex flex-col">
      <Background />
      {/* Header */}
      <header className="px-5 py-3 bg-slate-950/40 backdrop-blur-md border-b border-white/5 flex justify-between items-center sticky top-0 z-30">
        <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setGameState(p => ({...p, status: 'idle'}))}>
            <div className="w-9 h-9 bg-gradient-to-br from-fuchsia-600 to-cyan-600 rounded-lg flex items-center justify-center font-black text-xs shadow-lg group-hover:scale-105 transition-transform">
                PC
            </div>
            <div className="flex flex-col">
                <span className="font-bold text-sm leading-none text-slate-200">{gameState.puzzle?.theme}</span>
                <span className="text-[10px] text-slate-500 font-bold uppercase leading-none mt-1 tracking-wider">{gameState.settings.difficulty}</span>
            </div>
        </div>
        <div className="flex items-center gap-4 text-sm font-mono text-slate-300 bg-black/20 px-3 py-1.5 rounded-full border border-white/5">
            {gameState.isDaily && <span className="text-amber-400 font-bold flex items-center gap-1 text-[10px] uppercase tracking-widest"><Zap size={12}/> Daily</span>}
            <span>{Math.floor(gameState.timer / 60)}:{(gameState.timer % 60).toString().padStart(2, '0')}</span>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-lg mx-auto w-full p-4 flex flex-col gap-5">

        {/* Clue Bar */}
        <div className="glass-panel p-5 rounded-2xl min-h-[6rem] flex flex-col justify-center shadow-lg relative overflow-hidden transition-all group">
          <div className="absolute top-0 left-0 bottom-0 w-1 bg-gradient-to-b from-fuchsia-500 to-cyan-500"></div>
          <div className="flex justify-between items-start mb-1.5 pl-3">
             <span className="text-[10px] font-black uppercase text-fuchsia-400 tracking-[0.2em]">
               {gameState.direction}
             </span>
             {isAiThinking && <Loader2 size={16} className="animate-spin text-cyan-400"/>}
          </div>
          <p className="text-lg md:text-xl font-medium leading-snug text-white pl-3 drop-shadow-sm">
            {currentClue ? (
                <span>
                    <span className="font-mono text-slate-500 mr-2 text-base">{currentClue.number}</span>
                    {currentClue.text}
                </span>
            ) : 'Select a cell'}
          </p>

          {aiHint && (
             <div className="absolute inset-0 bg-slate-900/95 backdrop-blur-md p-5 flex items-center justify-between animate-[fade-in_0.2s_ease-out] z-20 border border-cyan-500/30">
                 <div className="flex gap-3 items-center">
                    <Sparkles size={18} className="text-cyan-400 shrink-0" />
                    <p className="text-sm text-cyan-100 italic">"{aiHint}"</p>
                 </div>
                 <button onClick={() => setAiHint(null)} className="text-[10px] font-bold uppercase bg-slate-800 hover:bg-slate-700 px-3 py-1.5 rounded border border-white/10 transition-colors">Close</button>
             </div>
          )}
        </div>

        {/* Grid Area */}
        <div className="flex-1 flex flex-col items-center justify-center min-h-[340px]">
            {gameState.status === 'completed' ? (
                <div className="text-center animate-[fade-in_0.5s_ease-out] w-full">
                    <div className="relative inline-block mb-6">
                        <div className="absolute inset-0 bg-yellow-500/30 blur-2xl rounded-full"></div>
                        <Trophy size={80} className="relative text-yellow-400 drop-shadow-[0_0_15px_rgba(250,204,21,0.8)]" />
                    </div>
                    <h2 className="text-4xl font-black text-transparent bg-clip-text bg-gradient-to-r from-yellow-200 to-yellow-500 mb-2">PUZZLE SOLVED!</h2>

                    <div className="glass-panel rounded-2xl p-6 mb-8 max-w-xs mx-auto shadow-2xl border border-yellow-500/20">
                        <div className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-2">Total Score</div>
                        <div className="text-5xl font-black text-white mb-6 font-mono text-glow">{gameState.score.toLocaleString()}</div>

                        <div className="space-y-3 text-xs text-slate-400 border-t border-white/10 pt-4 font-mono">
                            <div className="flex justify-between">
                                <span>Time Bonus</span>
                                <span className="text-emerald-400">+{Math.max(0, 500 - (gameState.timer * 2))}</span>
                            </div>
                            <div className="flex justify-between">
                                <span>Hints Penalty</span>
                                <span className="text-red-400">-{gameState.hintsUsed * HINT_PENALTY}</span>
                            </div>
                            <div className="flex justify-between">
                                <span>Base Points</span>
                                <span className="text-slate-300">+{BASE_WIN_POINTS}</span>
                            </div>
                        </div>
                    </div>

                    <div className="flex gap-4 justify-center">
                        <button onClick={() => setGameState(prev => ({...prev, status: 'idle'}))} className="bg-gradient-to-r from-fuchsia-600 to-purple-600 hover:from-fuchsia-500 hover:to-purple-500 text-white px-8 py-4 rounded-xl font-bold flex items-center gap-2 shadow-[0_0_20px_rgba(192,38,211,0.4)] transition-all hover:scale-105">
                            <Play size={18} fill="currentColor" /> MAIN MENU
                        </button>
                    </div>
                </div>
            ) : (
                <PuzzleGrid 
                    grid={gameState.grid} 
                    onCellClick={handleCellClick}
                />
            )}
        </div>

        {/* Game Controls */}
        {gameState.status === 'playing' && (
            <div className="space-y-4 animate-[fade-in_0.4s_ease-out_0.2s] fill-mode-backwards">
                <div className="flex justify-between items-center px-1">
                     <button 
                       onClick={handleAskAI}
                       disabled={isAiThinking}
                       className="flex items-center gap-2 text-cyan-300 text-[10px] font-bold uppercase tracking-wider hover:text-white disabled:opacity-50 px-4 py-2.5 bg-cyan-950/40 rounded-lg border border-cyan-500/20 hover:bg-cyan-900/40 transition-all hover:shadow-[0_0_10px_rgba(34,211,238,0.2)]"
                     >
                        <Sparkles size={14} /> 
                        Hint <span className="text-cyan-500/70">-{HINT_PENALTY}</span>
                     </button>

                     <div className="flex gap-3">
                        <button 
                            onClick={handleRevealLetter}
                            className="flex items-center gap-2 text-amber-300 text-[10px] font-bold uppercase tracking-wider hover:text-white px-4 py-2.5 bg-amber-950/40 rounded-lg border border-amber-500/20 hover:bg-amber-900/40 transition-all"
                        >
                            <Type size={14} /> Letter <span className="text-amber-500/70">-{REVEAL_LETTER_PENALTY}</span>
                        </button>
                         <button 
                            onClick={handleRevealWord}
                            className="flex items-center gap-2 text-rose-300 text-[10px] font-bold uppercase tracking-wider hover:text-white px-4 py-2.5 bg-rose-950/40 rounded-lg border border-rose-500/20 hover:bg-rose-900/40 transition-all"
                        >
                            <AlertCircle size={14} /> Word <span className="text-rose-500/70">-{REVEAL_WORD_PENALTY}</span>
                        </button>
                     </div>
                </div>

                <VirtualKeyboard 
                    onKeyPress={handleInput} 
                    onDelete={handleBackspace} 
                />
            </div>
        )}
      </main>
    </div>
  );
}

import React from 'react';
import { CellData } from '../types';

interface PuzzleGridProps {
  grid: CellData[][];
  onCellClick: (row: number, col: number) => void;
}

export const PuzzleGrid: React.FC<PuzzleGridProps> = ({ grid, onCellClick }) => {
  const size = grid.length;

  // Dynamic text sizing based on grid dimension
  const getTextSize = () => {
    if (size <= 4) return 'text-3xl';
    if (size === 5) return 'text-2xl';
    if (size === 6) return 'text-xl';
    return 'text-lg';
  };

  const textSize = getTextSize();

  return (
    <div className="relative perspective-[1200px] py-8 mx-auto w-full flex justify-center">
      <div 
        className="grid gap-3 p-6 rounded-3xl transition-all transform rotate-x-12 hover:rotate-x-0 duration-500 ease-out"
        style={{
          gridTemplateColumns: `repeat(${size}, minmax(0, 1fr))`,
          maxWidth: size > 5 ? '420px' : '380px',
          width: '100%',
          background: 'rgba(0,0,0,0.2)',
          boxShadow: '0 20px 50px -10px rgba(0,0,0,0.5)',
          border: '1px solid rgba(255,255,255,0.05)'
        }}
      >
        {grid.map((row, rIndex) => (
          row.map((cell, cIndex) => (
            <div
              key={`${rIndex}-${cIndex}`}
              onClick={() => onCellClick(rIndex, cIndex)}
              className={`
                relative aspect-square flex items-center justify-center ${textSize} font-bold uppercase cursor-pointer select-none
                transition-all duration-150 cubic-bezier(0.4, 0, 0.2, 1)
                rounded-xl border-t border-l border-r border-white/10

                ${cell.active 
                  ? 'bg-gradient-to-br from-fuchsia-500 to-fuchsia-700 text-white translate-y-[4px] shadow-[0_0_15px_rgba(217,70,239,0.6)] border-b-0' 
                  : cell.related 
                      ? 'bg-slate-800 text-fuchsia-200 border-b-[6px] border-slate-950 translate-y-0 hover:translate-y-[2px] hover:border-b-[4px]' 
                      : 'bg-slate-800 text-slate-300 border-b-[6px] border-slate-950 translate-y-0 hover:translate-y-[2px] hover:border-b-[4px] hover:bg-slate-700'}

                ${cell.isCorrect && !cell.active ? 'bg-gradient-to-br from-emerald-600 to-emerald-800 text-white border-emerald-950' : ''}
                ${cell.isRevealed && !cell.isCorrect ? 'text-yellow-400' : ''}

                ${cell.active ? '' : 'shadow-[0_10px_0_rgba(0,0,0,0.3)]'}
              `}
            >
              {/* Number Label */}
              {cell.number && (
                <span className={`absolute top-1 left-1.5 ${size >= 6 ? 'text-[8px]' : 'text-[10px]'} font-mono text-white/60 leading-none pointer-events-none drop-shadow-md`}>
                  {cell.number}
                </span>
              )}

              {/* Value with text shadow for depth */}
              <span className={`
                  ${size >= 6 ? 'mt-0' : 'mt-0.5'} 
                  drop-shadow-[0_2px_0_rgba(0,0,0,0.3)]
                  ${cell.active ? 'drop-shadow-none' : ''}
              `}>
                  {cell.userValue}
              </span>

              {/* Shine effect on top */}
              <div className="absolute inset-x-0 top-0 h-[1px] bg-gradient-to-r from-transparent via-white/40 to-transparent opacity-50" />
            </div>
          ))
        ))}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { GameState, CellData, Direction, Topic, PuzzleData, GameSettings, UserStats } from './types';
import { generatePuzzle, getHintForCell } from './services/geminiService';
import { PuzzleGrid } from './components/PuzzleGrid';
import { VirtualKeyboard } from './components/VirtualKeyboard';
import { 
  Clapperboard, Music, Tv, Loader2, Sparkles, Trophy, 
  Share2, Play, Zap, Calendar, Globe, Eye, Type, AlertCircle, Save 
} from 'lucide-react';

const TOPICS: { id: Topic; icon: React.ReactNode; label: string; color: string }[] = [
  { id: 'Movies', icon: <Clapperboard size={18} />, label: 'Movies', color: 'text-pink-400' },
  { id: 'TV Shows', icon: <Tv size={18} />, label: 'TV', color: 'text-blue-400' },
  { id: 'Music', icon: <Music size={18} />, label: 'Music', color: 'text-purple-400' },
  { id: '90s Pop Culture', icon: <Sparkles size={18} />, label: '90s', color: 'text-yellow-400' },
  { id: 'Modern Hits', icon: <Zap size={18} />, label: 'Modern', color: 'text-cyan-400' },
  { id: 'Sci-Fi', icon: <Globe size={18} />, label: 'Sci-Fi', color: 'text-green-400' },
  { id: 'Reality TV', icon: <Eye size={18} />, label: 'Reality', color: 'text-orange-400' },
  { id: 'Superheroes', icon: <Zap size={18} />, label: 'Heroes', color: 'text-red-400' },
  { id: 'Classic Rock', icon: <Music size={18} />, label: 'Rock', color: 'text-amber-400' },
];

const INITIAL_STATS: UserStats = {
  totalPoints: 0,
  gamesPlayed: 0,
  gamesWon: 0,
  currentStreak: 0,
  maxStreak: 0,
  lastDailyDate: null,
};

const BASE_WIN_POINTS = 1000;
const HINT_PENALTY = 50;
const REVEAL_LETTER_PENALTY = 100;
const REVEAL_WORD_PENALTY = 200;

export default function App() {
  const [stats, setStats] = useState<UserStats>(INITIAL_STATS);
  const [gameState, setGameState] = useState<GameState>({
    status: 'idle',
    puzzle: null,
    grid: [],
    selectedCell: null,
    direction: 'across',
    timer: 0,
    hintsUsed: 0,
    revealsUsed: 0,
    score: 0,
    isDaily: false,
    settings: {
      difficulty: 'Medium',
      region: 'Global'
    }
  });

  const [aiHint, setAiHint] = useState<string | null>(null);
  const [isAiThinking, setIsAiThinking] = useState(false);
  const [savedGameExists, setSavedGameExists] = useState(false);

  // Load Persistence
  useEffect(() => {
    const savedStats = localStorage.getItem('popcross_stats_v1');
    if (savedStats) setStats(JSON.parse(savedStats));

    const savedGame = localStorage.getItem('popcross_save_v1');
    if (savedGame) setSavedGameExists(true);
  }, []);

  // Save Stats
  useEffect(() => {
    localStorage.setItem('popcross_stats_v1', JSON.stringify(stats));
  }, [stats]);

  // Save Game Progress
  useEffect(() => {
    if (gameState.status === 'playing') {
      localStorage.setItem('popcross_save_v1', JSON.stringify(gameState));
    } else if (gameState.status === 'completed' || gameState.status === 'idle') {
      if (gameState.status === 'completed') {
        localStorage.removeItem('popcross_save_v1');
        setSavedGameExists(false);
      }
    }
  }, [gameState]);

  // Timer
  useEffect(() => {
    let interval: number;
    if (gameState.status === 'playing') {
      interval = window.setInterval(() => {
        setGameState(prev => ({ ...prev, timer: prev.timer + 1 }));
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [gameState.status]);

  const resumeGame = () => {
    const saved = localStorage.getItem('popcross_save_v1');
    if (saved) {
      setGameState(JSON.parse(saved));
    }
  };

  const startNewGame = async (topic: string, isDaily: boolean = false) => {
    setGameState(prev => ({ 
      ...prev, 
      status: 'generating', 
      hintsUsed: 0, 
      revealsUsed: 0, 
      timer: 0,
      score: 0,
      isDaily
    }));
    setAiHint(null);

    try {
      const theme = isDaily ? "Daily Mix" : topic;
      const puzzle = await generatePuzzle(theme, gameState.settings.difficulty, gameState.settings.region);

      const newGrid: CellData[][] = puzzle.grid.map((row, r) => 
        row.map((char, c) => ({
          row: r,
          col: c,
          value: char,
          userValue: '',
          isBlack: false,
          number: null,
          active: false,
          related: false,
          isCorrect: false,
          isRevealed: false
        }))
      );

      puzzle.clues.forEach(clue => {
         if (newGrid[clue.row][clue.col]) {
             newGrid[clue.row][clue.col].number = clue.number;
         }
      });

      const newState: GameState = {
        ...gameState,
        status: 'playing',
        puzzle,
        grid: newGrid,
        selectedCell: { row: 0, col: 0 },
        direction: 'across',
        timer: 0,
        hintsUsed: 0,
        revealsUsed: 0,
        score: 0,
        isDaily,
      };

      setGameState(newState);
      updateSelectionHighlights(newGrid, { row: 0, col: 0 }, 'across', newState);

    } catch (error) {
      console.error(error);
      setGameState(prev => ({ ...prev, status: 'idle' }));
      alert("Failed to generate puzzle. Please check your API key or try again.");
    }
  };

  const updateSelectionHighlights = (
    currentGrid: CellData[][], 
    selected: { row: number, col: number } | null, 
    dir: Direction,
    stateOverride?: GameState
  ) => {
    if (!selected) return;

    const newGrid = currentGrid.map(row => row.map(cell => ({ ...cell, active: false, related: false })));
    newGrid[selected.row][selected.col].active = true;

    if (dir === 'across') {
      newGrid[selected.row].forEach(cell => cell.related = true);
    } else {
      newGrid.forEach(row => {
        if (row[selected.col]) row[selected.col].related = true;
      });
    }

    setGameState(prev => ({ 
        ...(stateOverride || prev), 
        grid: newGrid, 
        selectedCell: selected, 
        direction: dir 
    }));
  };

  const handleCellClick = (row: number, col: number) => {
    if (gameState.status !== 'playing') return;
    if (gameState.selectedCell?.row === row && gameState.selectedCell?.col === col) {
      const newDir = gameState.direction === 'across' ? 'down' : 'across';
      updateSelectionHighlights(gameState.grid, { row, col }, newDir);
    } else {
      updateSelectionHighlights(gameState.grid, { row, col }, gameState.direction);
    }
  };

  const checkWinCondition = (grid: CellData[][]) => {
    const allCorrect = grid.every(row => row.every(cell => cell.userValue === cell.value));
    if (allCorrect) {
      const timeBonus = Math.max(0, 500 - (gameState.timer * 2));
      const finalScore = Math.max(0, BASE_WIN_POINTS + timeBonus - gameState.score); 

      setGameState(prev => ({ ...prev, status: 'completed', score: finalScore }));

      const today = new Date().toISOString().split('T')[0];
      setStats(prev => {
        const isNewDay = prev.lastDailyDate !== today;
        let newStreak = prev.currentStreak;
        if (gameState.isDaily && isNewDay) newStreak += 1;

        return {
          totalPoints: prev.totalPoints + finalScore,
          gamesPlayed: prev.gamesPlayed + 1,
          gamesWon: prev.gamesWon + 1,
          currentStreak: newStreak,
          maxStreak: Math.max(prev.maxStreak, newStreak),
          lastDailyDate: gameState.isDaily ? today : prev.lastDailyDate
        };
      });
    }
  };

  const handleInput = useCallback((char: string) => {
    if (gameState.status !== 'playing' || !gameState.selectedCell) return;
    const { row, col } = gameState.selectedCell;

    if (gameState.grid[row][col].isRevealed) return;

    const newGrid = [...gameState.grid];
    newGrid[row][col] = { 
        ...newGrid[row][col], 
        userValue: char, 
        isCorrect: char === newGrid[row][col].value 
    };

    let nextRow = row;
    let nextCol = col;
    if (gameState.direction === 'across') {
       if (col < newGrid.length - 1) nextCol++;
    } else {
       if (row < newGrid.length - 1) nextRow++;
    }

    updateSelectionHighlights(newGrid, { row: nextRow, col: nextCol }, gameState.direction);
    checkWinCondition(newGrid);
  }, [gameState]);

  const handleBackspace = useCallback(() => {
    if (gameState.status !== 'playing' || !gameState.selectedCell) return;
    const { row, col } = gameState.selectedCell;
    const newGrid = [...gameState.grid];

    if (newGrid[row][col].isRevealed) return;

    if (newGrid[row][col].userValue === '') {
        let prevRow = row;
        let prevCol = col;
        if (gameState.direction === 'across') {
            if (col > 0) prevCol--;
        } else {
            if (row > 0) prevRow--;
        }
        updateSelectionHighlights(newGrid, { row: prevRow, col: prevCol }, gameState.direction);
    } else {
        newGrid[row][col].userValue = '';
        setGameState(prev => ({ ...prev, grid: newGrid }));
    }
  }, [gameState]);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
        if (gameState.status !== 'playing') return;
        if (e.key.match(/^[a-zA-Z]$/)) handleInput(e.key.toUpperCase());
        else if (e.key === 'Backspace') handleBackspace();
        else if (e.key === 'ArrowUp') {
            const r = Math.max(0, (gameState.selectedCell?.row || 0) - 1);
            updateSelectionHighlights(gameState.grid, {row: r, col: gameState.selectedCell?.col || 0}, gameState.direction);
        } else if (e.key === 'ArrowDown') {
            const r = Math.min(gameState.grid.length - 1, (gameState.selectedCell?.row || 0) + 1);
            updateSelectionHighlights(gameState.grid, {row: r, col: gameState.selectedCell?.col || 0}, gameState.direction);
        } else if (e.key === 'ArrowLeft') {
            const c = Math.max(0, (gameState.selectedCell?.col || 0) - 1);
            updateSelectionHighlights(gameState.grid, {row: gameState.selectedCell?.row || 0, col: c}, gameState.direction);
        } else if (e.key === 'ArrowRight') {
            const c = Math.min(gameState.grid.length - 1, (gameState.selectedCell?.col || 0) + 1);
            updateSelectionHighlights(gameState.grid, {row: gameState.selectedCell?.row || 0, col: c}, gameState.direction);
        }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [gameState, handleInput, handleBackspace]);


  const getCurrentClue = () => {
    if (!gameState.puzzle || !gameState.selectedCell) return null;
    const { row, col } = gameState.selectedCell;
    return gameState.puzzle.clues.find(c => {
      if (gameState.direction === 'across') return c.row === row && c.direction === 'across';
      if (gameState.direction === 'down') return c.col === col && c.direction === 'down';
      return false;
    });
  };

  const handleAskAI = async () => {
      const clue = getCurrentClue();
      if (!clue || isAiThinking) return;
      setIsAiThinking(true);
      let pattern = "";
      if (gameState.direction === 'across') {
          pattern = gameState.grid[clue.row].map(c => c.userValue || "_").join(" ");
      } else {
          gameState.grid.forEach(r => { pattern += (r[clue.col].userValue || "_") + " "; });
      }
      try {
          const hint = await getHintForCell(clue.text, pattern);
          setAiHint(hint);
          setGameState(prev => ({ 
              ...prev, 
              hintsUsed: prev.hintsUsed + 1,
              score: prev.score + HINT_PENALTY 
          }));
      } catch (e) {
          setAiHint("Could not fetch hint.");
      } finally {
          setIsAiThinking(false);
      }
  };

  const handleRevealLetter = () => {
      if (!gameState.selectedCell) return;
      const { row, col } = gameState.selectedCell;
      if (gameState.grid[row][col].userValue === gameState.grid[row][col].value) return;

      const newGrid = [...gameState.grid];
      newGrid[row][col] = {
          ...newGrid[row][col],
          userValue: newGrid[row][col].value,
          isCorrect: true,
          isRevealed: true
      };

      setGameState(prev => ({
          ...prev,
          grid: newGrid,
          score: prev.score + REVEAL_LETTER_PENALTY
      }));
      checkWinCondition(newGrid);
  };

  const handleRevealWord = () => {
      if (!gameState.selectedCell) return;
      const { row, col } = gameState.selectedCell;
      const newGrid = [...gameState.grid];

      if (gameState.direction === 'across') {
          newGrid[row].forEach(cell => {
              cell.userValue = cell.value;
              cell.isCorrect = true;
              cell.isRevealed = true;
          });
      } else {
          newGrid.forEach(r => {
              r[col].userValue = r[col].value;
              r[col].isCorrect = true;
              r[col].isRevealed = true;
          });
      }

      setGameState(prev => ({
          ...prev,
          grid: newGrid,
          score: prev.score + REVEAL_WORD_PENALTY
      }));
      checkWinCondition(newGrid);
  };

  const currentClue = getCurrentClue();
  const isDailyDone = stats.lastDailyDate === new Date().toISOString().split('T')[0];

  // ---------------- RENDER ----------------

  // Background Element
  const Background = () => (
      <div className="fixed inset-0 pointer-events-none z-[-1]">
          {/* Deep Gradient Background */}
          <div className="absolute inset-0 bg-gradient-to-br from-[#0f0c29] via-[#302b63] to-[#24243e] opacity-90" />

          {/* Animated Glow Blobs */}
          <div className="absolute top-[-10%] left-[-10%] w-[500px] h-[500px] bg-fuchsia-600/20 rounded-full blur-[120px] mix-blend-screen" />
          <div className="absolute bottom-[-10%] right-[-10%] w-[500px] h-[500px] bg-cyan-600/20 rounded-full blur-[120px] mix-blend-screen" />
      </div>
  );

  if (gameState.status === 'idle') {
    return (
      <div className="min-h-screen text-white flex flex-col items-center p-6 relative overflow-y-auto">
        <Background />

        <div className="z-10 text-center max-w-lg w-full mt-12 animate-[fade-in_0.6s_ease-out]">
          <h1 className="text-6xl md:text-7xl font-black mb-2 tracking-tighter text-transparent bg-clip-text bg-gradient-to-r from-fuchsia-300 via-white to-cyan-300 drop-shadow-[0_0_25px_rgba(217,70,239,0.5)]">
            POPCROSS
          </h1>
          <p className="text-slate-300 text-lg mb-10 font-medium tracking-wide">INFINITE CULTURE PUZZLES</p>

          {/* Stats Bar */}
          <div className="flex justify-center gap-0 mb-10 glass-panel rounded-2xl p-1 shadow-2xl">
             <div className="flex-1 text-center py-3 px-6 border-r border-white/10">
                 <div className="flex items-center justify-center gap-2 text-yellow-400 font-bold text-2xl font-mono text-glow">
                     <Zap size={22} fill="currentColor" /> {stats.currentStreak}
                 </div>
                 <div className="text-[10px] uppercase text-slate-400 font-bold tracking-widest mt-1">Daily Streak</div>
             </div>
             <div className="flex-1 text-center py-3 px-6">
                 <div className="flex items-center justify-center gap-2 text-cyan-400 font-bold text-2xl font-mono text-glow">
                     <Trophy size={22} /> {stats.totalPoints.toLocaleString()}
                 </div>
                 <div className="text-[10px] uppercase text-slate-400 font-bold tracking-widest mt-1">Total Score</div>
             </div>
          </div>

          <div className="space-y-6 mb-10">
             {/* Settings */}
             <div className="glass-panel p-4 rounded-xl space-y-4">
                 <div className="flex flex-col gap-2">
                     <label className="text-[10px] text-slate-400 uppercase font-bold tracking-widest ml-1">Difficulty</label>
                     <div className="flex bg-black/40 rounded-lg p-1 border border-white/5">
                         {['Easy', 'Medium', 'Hard', 'Very Hard'].map((d) => (
                             <button 
                                key={d}
                                onClick={() => setGameState(p => ({...p, settings: {...p.settings, difficulty: d as any}}))}
                                className={`flex-1 py-2 text-[10px] sm:text-xs rounded-md transition-all font-bold ${gameState.settings.difficulty === d ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-900/50' : 'text-slate-500 hover:text-slate-300 hover:bg-white/5'}`}
                             >
                                 {d === 'Very Hard' ? 'X-HARD' : d.toUpperCase()}
                             </button>
                         ))}
                     </div>
                 </div>
                 <div className="flex flex-col gap-2">
                    <label className="text-[10px] text-slate-400 uppercase font-bold tracking-widest ml-1">Region</label>
                    <div className="flex bg-black/40 rounded-lg p-1 border border-white/5">
                        {['Global', 'USA', 'UK'].map((r) => (
                            <button 
                            key={r}
                            onClick={() => setGameState(p => ({...p, settings: {...p.settings, region: r as any}}))}
                            className={`flex-1 py-2 text-xs rounded-md transition-all font-bold ${gameState.settings.region === r ? 'bg-cyan-600 text-white shadow-lg shadow-cyan-900/50' : 'text-slate-500 hover:text-slate-300 hover:bg-white/5'}`}
                            >
                                {r.toUpperCase()}
                            </button>
                        ))}
                    </div>
                 </div>
             </div>
          </div>

          {/* Main Actions */}
          <div className="grid gap-4 mb-10">
              {savedGameExists && (
                  <button 
                    onClick={resumeGame}
                    className="w-full py-4 bg-slate-800/80 border border-fuchsia-500/50 text-fuchsia-300 rounded-xl font-bold flex items-center justify-center gap-3 hover:bg-fuchsia-900/20 hover:shadow-[0_0_20px_rgba(217,70,239,0.2)] transition-all group"
                  >
                      <Save size={20} className="group-hover:scale-110 transition-transform"/> RESUME SESSION
                  </button>
              )}

              <button 
                onClick={() => startNewGame("Daily Challenge", true)}
                disabled={isDailyDone}
                className={`w-full py-5 rounded-xl font-black text-lg tracking-wide flex items-center justify-center gap-3 border transition-all relative overflow-hidden group
                    ${isDailyDone 
                        ? 'bg-slate-900/50 border-slate-800 text-slate-600 cursor-not-allowed' 
                        : 'bg-gradient-to-r from-amber-600/20 to-orange-600/20 border-amber-500/50 text-amber-400 hover:border-amber-400 hover:shadow-[0_0_30px_rgba(245,158,11,0.3)]'
                    }
                `}
              >
                  {!isDailyDone && <div className="absolute inset-0 bg-amber-500/10 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700 blur-md"></div>}
                  <Calendar size={22} className={isDailyDone ? "" : "animate-pulse"}/> 
                  {isDailyDone ? "DAILY CHALLENGE COMPLETED" : "DAILY CHALLENGE"}
              </button>
          </div>

          <h2 className="text-xl font-bold mb-4 text-white/80 text-left border-b border-white/10 pb-2">Quick Play</h2>
          <div className="grid grid-cols-3 gap-3 pb-12">
            {TOPICS.map(topic => (
              <button
                key={topic.id}
                onClick={() => startNewGame(topic.id)}
                className="glass-panel hover:bg-white/10 border-white/5 hover:border-white/20 rounded-xl p-3 flex flex-col items-center justify-center gap-3 h-28 transition-all duration-200 group relative overflow-hidden"
              >
                <div className={`${topic.color} opacity-80 group-hover:opacity-100 group-hover:scale-110 transition-all duration-300 drop-shadow-lg`}>
                  {topic.icon}
                </div>
                <span className="font-bold text-xs text-slate-300 group-hover:text-white uppercase tracking-wider text-center leading-tight">{topic.label}</span>
              </button>
            ))}
          </div>
        </div>
      </div>
    );
  }

  if (gameState.status === 'generating') {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center text-white px-4 text-center">
        <Background />
        <div className="glass-panel p-8 rounded-2xl flex flex-col items-center shadow-2xl border border-fuchsia-500/30">
            <Loader2 size={56} className="animate-spin text-fuchsia-400 mb-6 drop-shadow-glow" />
            <h2 className="text-3xl font-bold animate-pulse mb-3 bg-clip-text text-transparent bg-gradient-to-r from-fuchsia-300 to-cyan-300">GENERATING</h2>
            <p className="text-slate-400 text-sm font-mono mb-4">Consulting the Archives...</p>
            <div className="flex gap-2 text-[10px] uppercase font-bold tracking-widest text-slate-500">
                <span className="px-3 py-1 bg-black/40 rounded border border-white/10">{gameState.settings.difficulty}</span>
                <span className="px-3 py-1 bg-black/40 rounded border border-white/10">{gameState.settings.region}</span>
            </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen text-white flex flex-col overflow-hidden">
      <Background />
      {/* Header */}
