import React from 'react';
import { CellData } from '../types';

interface PuzzleGridProps {
  grid: CellData[][];
  onCellClick: (row: number, col: number) => void;
}

export const PuzzleGrid: React.FC<PuzzleGridProps> = ({ grid, onCellClick }) => {
  const size = grid.length;

  // Dynamic text sizing based on grid dimension
  const getTextSize = () => {
    if (size <= 4) return 'text-4xl';
    if (size === 5) return 'text-3xl';
    if (size === 6) return 'text-2xl';
    return 'text-xl';
  };

  const textSize = getTextSize();

  return (
    <div className="flex justify-center items-center w-full h-full py-10" style={{ perspective: '1200px' }}>
      {/* The 3D Slab Container */}
      <div 
        className="relative transition-transform duration-500 ease-out"
        style={{
          transformStyle: 'preserve-3d',
          transform: 'rotateX(20deg) rotateY(0deg)',
          maxWidth: size > 5 ? '480px' : '400px',
          width: '100%',
        }}
      >
        {/* Side Thickness of the Slab */}
        <div 
            className="absolute inset-0 bg-slate-900 rounded-lg shadow-2xl"
            style={{ 
                transform: 'translateZ(-20px)',
                boxShadow: '0 30px 60px -10px rgba(0,0,0,0.8)'
            }}
        />
        {/* Thickness layers for "physicality" */}
        <div className="absolute inset-x-0 bottom-0 h-[20px] bg-slate-950/80 rounded-b-lg origin-bottom transform rotate-x-[-90deg] translate-y-full" />
        <div className="absolute inset-y-0 right-0 w-[20px] bg-slate-950/80 rounded-r-lg origin-right transform rotate-y-[90deg] translate-x-full" />
        <div className="absolute inset-y-0 left-0 w-[20px] bg-slate-800 rounded-l-lg origin-left transform rotate-y-[-90deg] translate-x-[-100%]" />


        {/* The Grid Surface */}
        <div 
          className="grid gap-[2px] p-[6px] bg-slate-800 rounded-lg border-2 border-slate-700/50"
          style={{
            gridTemplateColumns: `repeat(${size}, minmax(0, 1fr))`,
            transform: 'translateZ(0)',
            backfaceVisibility: 'hidden',
          }}
        >
          {grid.map((row, rIndex) => (
            row.map((cell, cIndex) => {
              const isActive = cell.active;
              const isRelated = cell.related;
              const isCorrect = cell.isCorrect;

              // Base Styles
              let bgClass = 'bg-[#1a1f2e]'; // Dark blue-grey
              let textClass = 'text-slate-400';
              let glowClass = '';

              if (isActive) {
                  bgClass = 'bg-fuchsia-600';
                  textClass = 'text-white';
                  glowClass = 'shadow-[inset_0_0_20px_rgba(0,0,0,0.2)]';
              } else if (isCorrect) {
                  bgClass = 'bg-emerald-900/40';
                  textClass = 'text-emerald-400';
              } else if (isRelated) {
                  bgClass = 'bg-slate-800';
                  textClass = 'text-fuchsia-200';
              }

              if (cell.isRevealed && !isCorrect) {
                  textClass = 'text-yellow-400';
              }

              // Corner logic for rounding the grid edges
              const isTL = rIndex === 0 && cIndex === 0;
              const isTR = rIndex === 0 && cIndex === size - 1;
              const isBL = rIndex === size - 1 && cIndex === 0;
              const isBR = rIndex === size - 1 && cIndex === size - 1;
              const roundedClass = `
                ${isTL ? 'rounded-tl-md' : ''}
                ${isTR ? 'rounded-tr-md' : ''}
                ${isBL ? 'rounded-bl-md' : ''}
                ${isBR ? 'rounded-br-md' : ''}
              `;

              return (
                <div
                  key={`${rIndex}-${cIndex}`}
                  onClick={() => onCellClick(rIndex, cIndex)}
                  className={`
                    relative aspect-square flex items-center justify-center 
                    cursor-pointer select-none transition-colors duration-150
                    ${bgClass} ${textClass} ${textSize} ${roundedClass}
                    font-bold uppercase
                    hover:brightness-110
                    ${glowClass}
                  `}
                >
                  {/* Inner bevel/depth effect for "Barred" look */}
                  <div className="absolute inset-0 shadow-[inset_1px_1px_0_rgba(255,255,255,0.05),inset_-1px_-1px_0_rgba(0,0,0,0.3)] pointer-events-none" />

                  {/* Active highlight border (The "Bar" feel) */}
                  {isActive && (
                      <div className="absolute inset-0 border-[3px] border-white/20 animate-pulse pointer-events-none" />
                  )}

                  {/* Number Label */}
                  {cell.number && (
                    <span className={`absolute top-1 left-1.5 ${size >= 6 ? 'text-[8px]' : 'text-[10px]'} font-mono opacity-50 leading-none`}>
                      {cell.number}
                    </span>
                  )}

                  <span className="relative z-10">{cell.userValue}</span>
                </div>
              );
            })
          ))}
        </div>
      </div>
    </div>
  );
};

