import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PuzzleData, Clue, Difficulty, Region } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const getGridSize = (difficulty: Difficulty): number => {
  switch (difficulty) {
    case 'Easy': return 5;      // Mini
    case 'Medium': return 7;    // Midi
    case 'Hard': return 7;      // Midi Dense
    case 'Expert': return 10;   // Standard (Requires black squares)
    default: return 5;
  }
};

const getPuzzleSchema = (size: number): Schema => {
  return {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING, description: "A witty, pop-culture themed title" },
      rows: {
        type: Type.ARRAY,
        description: `${size} strings, each exactly ${size} chars long. Use '.' for black squares/voids. Uppercase letters for answers.`,
        items: { type: Type.STRING }
      },
      acrossClues: {
        type: Type.ARRAY,
        description: "Clues for horizontal words. Format: 'RowIndex|ClueText'",
        items: { type: Type.STRING }
      },
      downClues: {
        type: Type.ARRAY,
        description: "Clues for vertical words. Format: 'ColIndex|ClueText'",
        items: { type: Type.STRING }
      }
    },
    required: ["title", "rows", "acrossClues", "downClues"]
  };
};

const getContextPrompts = (diff: Difficulty, region: Region, topic: string) => {
    let diffText = "";
    switch(diff) {
        case 'Easy': diffText = "Use very famous blockbusters, #1 hits, and main characters. Keep clues direct."; break;
        case 'Medium': diffText = "Use popular streaming shows, well-known lyrics, and celebrity trivia."; break;
        case 'Hard': diffText = "Deep cuts, B-sides, supporting actors, and directors."; break;
        case 'Expert': diffText = "Obscure trivia, industry facts, and clever wordplay. High difficulty."; break;
    }

    return `Topic: ${topic}. Difficulty: ${diffText}. Region Focus: ${region}.`;
}

export const generatePuzzle = async (topic: string, difficulty: Difficulty, region: Region): Promise<PuzzleData> => {
  const modelId = "gemini-3-flash-preview";
  const size = getGridSize(difficulty);
  const schema = getPuzzleSchema(size);

  const allowBlackSquares = size > 6;

  const prompt = `
    Create a pop-culture crossword puzzle.
    ${getContextPrompts(difficulty, region, topic)}

    Configuration:
    - Grid Size: ${size}x${size}.
    - ${allowBlackSquares ? "You MUST use black squares (represented by '.') to create a valid crossword grid layout." : "Create a dense grid (no black squares, every cell filled)."}
    - All words must be real words or proper nouns related to TV, Movies, or Music.

    IMPORTANT for Clues:
    - Provide clues for EVERY continuous word of 2 or more letters.
    - Since you are outputting the grid rows, you must calculate the clue numbers yourself or provide the clues in a list that I can parse.
    - RETURN Clues in the format "Index|ClueText". For across, Index is the Row number (0-based). For down, Index is the Column number (0-based).
    - If a row/col has multiple words (separated by black squares), combine the clues with ' / ' or handle logic to mapping. *Actually, simplify: Try to avoid multiple words per row/col for this specific task to ensure parsing reliability, or ensure the clue text covers the main word.*
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
        systemInstruction: "You are a master crossword constructor for a pop-culture magazine.",
      }
    });

    const json = JSON.parse(response.text || "{}");

    if (!json.rows || json.rows.length !== size) {
      throw new Error("Invalid puzzle generated");
    }

    // Convert string rows to 2D array
    const grid: string[][] = json.rows.map((row: string) => row.toUpperCase().split('').slice(0, size));
    const clues: Clue[] = [];

    let clueNumber = 1;
    const gridNumbers: (number | null)[][] = Array(size).fill(null).map(() => Array(size).fill(null));

    // Logic to assign numbers to the grid
    for (let r = 0; r < size; r++) {
        for (let c = 0; c < size; c++) {
            if (grid[r][c] === '.') continue;

            const isAcrossStart = (c === 0 || grid[r][c-1] === '.') && (c + 1 < size && grid[r][c+1] !== '.');
            const isDownStart = (r === 0 || grid[r-1][c] === '.') && (r + 1 < size && grid[r+1][c] !== '.');

            if (isAcrossStart || isDownStart) {
                gridNumbers[r][c] = clueNumber++;
            }
        }
    }

    // Map AI provided clues to the calculated numbers
    // Note: The AI returns "Row|Clue" format roughly. We need to match this to our actual words.
    // This is a simplification. For a perfect crossword, we'd extract words and match.
    // Fallback: We re-generate clues based on the grid words if needed, but let's try to map the AI ones.

    // Better approach: Ask AI for clues, but if they don't align perfectly, we use the text as a pool.
    // To make this robust, let's extract words and assume AI gave us relevant clues.

    // Extract Across Words
    for (let r = 0; r < size; r++) {
        let word = "";
        let startCol = -1;
        for (let c = 0; c <= size; c++) {
            if (c < size && grid[r][c] !== '.') {
                if (startCol === -1) startCol = c;
                word += grid[r][c];
            } else {
                if (word.length >= 2) {
                    // Find clue text from AI response (simplified matching)
                    const aiClue = json.acrossClues.find((s: string) => s.startsWith(`${r}|`)) || `${r}|Def: ${word}`;
                    const text = aiClue.split('|')[1] || `Clue for ${word}`;

                    clues.push({
                        number: gridNumbers[r][startCol]!,
                        direction: 'across',
                        text: text,
                        answer: word,
                        row: r,
                        col: startCol
                    });
                }
                word = "";
                startCol = -1;
            }
        }
    }

    // Extract Down Words
    for (let c = 0; c < size; c++) {
        let word = "";
        let startRow = -1;
        for (let r = 0; r <= size; r++) {
            if (r < size && grid[r][c] !== '.') {
                if (startRow === -1) startRow = r;
                word += grid[r][c];
            } else {
                if (word.length >= 2) {
                    const aiClue = json.downClues.find((s: string) => s.startsWith(`${c}|`)) || `${c}|Def: ${word}`;
                    const text = aiClue.split('|')[1] || `Clue for ${word}`;

                    clues.push({
                        number: gridNumbers[startRow][c]!,
                        direction: 'down',
                        text: text,
                        answer: word,
                        row: startRow,
                        col: c
                    });
                }
                word = "";
                startRow = -1;
            }
        }
    }

    return {
      title: json.title,
      theme: topic,
      gridSize: size,
      grid,
      clues
    };

  } catch (error) {
    console.error("Failed to generate puzzle:", error);
    throw error;
  }
};

export const getHintForCell = async (clue: string, currentAnswerPattern: string): Promise<string> => {
    const prompt = `The crossword clue is "${clue}". The answer pattern is "${currentAnswerPattern}" (where _ is unknown). Give me a very short, subtle hint without revealing the word.`;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
    });
    return response.text || "Try thinking about synonyms.";
}

import React from 'react';
import { CellData } from '../types';

interface PuzzleGridProps {
  grid: CellData[][];
  onCellClick: (row: number, col: number) => void;
}

export const PuzzleGrid: React.FC<PuzzleGridProps> = ({ grid, onCellClick }) => {
  const size = grid.length;

  // Dynamic text sizing based on grid dimension
  const getTextSize = () => {
    if (size <= 5) return 'text-3xl';
    if (size <= 7) return 'text-2xl';
    return 'text-lg';
  };

  const textSize = getTextSize();

  return (
    <div className="flex justify-center items-center w-full h-full py-4 px-2">
      <div 
        className="grid gap-[2px] p-2 bg-slate-950 rounded-xl border border-slate-800 shadow-2xl"
        style={{
          gridTemplateColumns: `repeat(${size}, minmax(0, 1fr))`,
          maxWidth: size > 7 ? '550px' : '400px',
          width: '100%',
          aspectRatio: '1/1'
        }}
      >
        {grid.map((row, rIndex) => (
          row.map((cell, cIndex) => {
            if (cell.isBlack) {
                return (
                    <div 
                        key={`${rIndex}-${cIndex}`} 
                        className="bg-black/40 rounded-sm"
                    />
                );
            }

            const isActive = cell.active;
            const isRelated = cell.related;
            const isCorrect = cell.isCorrect;

            // Base Styles for 2D Block
            let bgClass = 'bg-slate-800';
            let textClass = 'text-slate-300';
            let borderClass = 'border-slate-700';
            let activeGlow = '';

            if (isActive) {
                bgClass = 'bg-fuchsia-600';
                textClass = 'text-white';
                borderClass = 'border-fuchsia-400';
                activeGlow = 'shadow-[0_0_15px_rgba(217,70,239,0.6)] z-20 scale-105';
            } else if (isCorrect) {
                bgClass = 'bg-emerald-600';
                textClass = 'text-white';
                borderClass = 'border-emerald-400';
            } else if (isRelated) {
                bgClass = 'bg-slate-700';
                textClass = 'text-fuchsia-200';
                borderClass = 'border-slate-600';
            }

            if (cell.isRevealed && !isCorrect) {
                textClass = 'text-yellow-400';
            }

            return (
              <div
                key={`${rIndex}-${cIndex}`}
                onClick={() => onCellClick(rIndex, cIndex)}
                className={`
                  relative flex items-center justify-center 
                  cursor-pointer select-none transition-all duration-150
                  ${bgClass} ${textClass} ${textSize} ${borderClass}
                  border rounded-md font-bold uppercase
                  hover:brightness-125
                  ${activeGlow}
                `}
              >
                {/* Number Label */}
                {cell.number && (
                  <span className={`absolute top-0.5 left-1 ${size >= 7 ? 'text-[8px]' : 'text-[10px]'} font-mono opacity-70 leading-none`}>
                    {cell.number}
                  </span>
                )}

                <span className="relative z-10 translate-y-[1px]">{cell.userValue}</span>
              </div>
            );
          })
        ))}
      </div>
    </div>
  );
};

