import React from 'react';
import { CellData } from '../types';

interface PuzzleGridProps {
  grid: CellData[][];
  onCellClick: (row: number, col: number) => void;
}

export const PuzzleGrid: React.FC<PuzzleGridProps> = ({ grid, onCellClick }) => {
  const size = grid.length;

  // Dynamic text sizing based on grid dimension
  const getTextSize = () => {
    if (size <= 5) return 'text-3xl';
    if (size <= 7) return 'text-2xl';
    return 'text-lg';
  };

  const textSize = getTextSize();

  return (
    <div className="flex justify-center items-center w-full h-full py-4 px-2">
      <div 
        className="grid gap-[2px] p-2 bg-slate-950 rounded-xl border border-slate-800 shadow-2xl"
        style={{
          gridTemplateColumns: `repeat(${size}, minmax(0, 1fr))`,
          maxWidth: size > 7 ? '550px' : '400px',
          width: '100%',
          aspectRatio: '1/1'
        }}
      >
        {grid.map((row, rIndex) => (
          row.map((cell, cIndex) => {
            if (cell.isBlack) {
                return (
                    <div 
                        key={`${rIndex}-${cIndex}`} 
                        className="bg-black/40 rounded-sm"
                    />
                );
            }

            const isActive = cell.active;
            const isRelated = cell.related;
            const isWordComplete = cell.isWordComplete;
            const isError = cell.isError;
            const isRevealed = cell.isRevealed;

            // Base Styles for 2D Block
            let bgClass = 'bg-slate-800';
            let textClass = 'text-slate-300';
            let borderClass = 'border-slate-700';
            let activeGlow = '';

            if (isActive) {
                bgClass = 'bg-fuchsia-600';
                textClass = 'text-white';
                borderClass = 'border-fuchsia-400';
                activeGlow = 'shadow-[0_0_15px_rgba(217,70,239,0.6)] z-20 scale-105';
            } else if (isWordComplete) {
                bgClass = 'bg-emerald-600';
                textClass = 'text-white';
                borderClass = 'border-emerald-400';
            } else if (isError) {
                bgClass = 'bg-red-900/50';
                textClass = 'text-red-400';
                borderClass = 'border-red-500';
            } else if (isRelated) {
                bgClass = 'bg-slate-700';
                textClass = 'text-fuchsia-200';
                borderClass = 'border-slate-600';
            }

            // Visual feedback for revealed letters (if word not yet complete)
            if (isRevealed && !isWordComplete && !isActive) {
                textClass = 'text-yellow-400';
            }

            return (
              <div
                key={`${rIndex}-${cIndex}`}
                onClick={() => onCellClick(rIndex, cIndex)}
                className={`
                  relative flex items-center justify-center 
                  cursor-pointer select-none transition-all duration-150
                  ${bgClass} ${textClass} ${textSize} ${borderClass}
                  border rounded-md font-bold uppercase
                  hover:brightness-125
                  ${activeGlow}
                `}
              >
                {/* Number Label */}
                {cell.number && (
                  <span className={`absolute top-0.5 left-1 ${size >= 7 ? 'text-[8px]' : 'text-[10px]'} font-mono opacity-70 leading-none`}>
                    {cell.number}
                  </span>
                )}

                <span className="relative z-10 translate-y-[1px]">{cell.userValue}</span>
              </div>
            );
          })
        ))}
      </div>
    </div>
  );
};

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PuzzleData, Clue, Difficulty, Region } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const getGridSize = (difficulty: Difficulty): number => {
  switch (difficulty) {
    case 'Easy': return 6;      // increased from 5
    case 'Medium': return 8;    // increased from 6
    case 'Hard': return 10;     // increased from 8
    case 'Expert': return 12;   // increased from 10
    default: return 6;
  }
};

const getPuzzleSchema = (size: number): Schema => {
  return {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING, description: "A witty title" },
      rows: {
        type: Type.ARRAY,
        description: `${size} strings, each ${size} chars. '.' for black squares. Uppercase letters.`,
        items: { type: Type.STRING }
      },
      acrossClues: {
        type: Type.ARRAY,
        description: "Strings like 'RowIndex|ClueText'",
        items: { type: Type.STRING }
      },
      downClues: {
        type: Type.ARRAY,
        description: "Strings like 'ColIndex|ClueText'",
        items: { type: Type.STRING }
      }
    },
    required: ["title", "rows", "acrossClues", "downClues"]
  };
};

const getContextPrompts = (diff: Difficulty, region: Region, topic: string) => {
    return `Topic: ${topic}. Difficulty: ${diff}. Region: ${region}.`;
}

export const generatePuzzle = async (topic: string, difficulty: Difficulty, region: Region): Promise<PuzzleData> => {
  const modelId = "gemini-3-flash-preview";
  const size = getGridSize(difficulty);
  const schema = getPuzzleSchema(size);

  // Prompt optimized for speed but now requesting higher density and difficulty
  const prompt = `
    Generate a ${size}x${size} crossword grid for topic: "${topic}".

    Instructions:
    1. Grid Style: "Blocked". Use black squares ('.') to separate words.
    2. Density: High. Try to fit as many words as possible into the grid. Avoid excessive black squares.
    3. Symmetry: Not required.
    4. Validation: Ensure all intersecting letters match perfectly.

    Content Strategy:
    - Topic: ${topic} (${region} context).
    - Difficulty: ${difficulty}.
    ${difficulty === 'Hard' || difficulty === 'Expert' 
      ? "- Use less common words and more challenging, clever, or punny clues." 
      : "- Use common words and direct clues."}

    Output Requirements:
    - 'rows': Array of ${size} strings representing the grid rows.
    - 'acrossClues': Array of strings formatted as "RowIndex|Clue Text". Example: "0|A famous movie star".
    - 'downClues': Array of strings formatted as "ColIndex|Clue Text".

    Ensure every word formed by 2+ continuous letters has a clue.
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: schema,
        thinkingConfig: { thinkingBudget: 0 } // Disable thinking for maximum speed
      }
    });

    const json = JSON.parse(response.text || "{}");

    if (!json.rows || json.rows.length !== size) {
      throw new Error("Invalid puzzle generated");
    }

    // Convert string rows to 2D array
    const grid: string[][] = json.rows.map((row: string) => row.toUpperCase().split('').slice(0, size));
    const clues: Clue[] = [];

    let clueNumber = 1;
    const gridNumbers: (number | null)[][] = Array(size).fill(null).map(() => Array(size).fill(null));

    // Logic to assign numbers to the grid
    for (let r = 0; r < size; r++) {
        for (let c = 0; c < size; c++) {
            if (grid[r][c] === '.') continue;

            const isAcrossStart = (c === 0 || grid[r][c-1] === '.') && (c + 1 < size && grid[r][c+1] !== '.');
            const isDownStart = (r === 0 || grid[r-1][c] === '.') && (r + 1 < size && grid[r+1][c] !== '.');

            if (isAcrossStart || isDownStart) {
                gridNumbers[r][c] = clueNumber++;
            }
        }
    }

    // Extract Across Words & Match Clues
    for (let r = 0; r < size; r++) {
        let word = "";
        let startCol = -1;
        for (let c = 0; c <= size; c++) {
            if (c < size && grid[r][c] !== '.') {
                if (startCol === -1) startCol = c;
                word += grid[r][c];
            } else {
                if (word.length >= 2) {
                    // Fuzzy match the clue from AI response
                    // We look for a clue that starts with "r|" or contains the word (fallback)
                    const aiClueStr = json.acrossClues.find((s: string) => s.startsWith(`${r}|`));
                    let text = aiClueStr ? aiClueStr.split('|')[1] : `Hint for ${word}`;

                    clues.push({
                        number: gridNumbers[r][startCol]!,
                        direction: 'across',
                        text: text,
                        answer: word,
                        row: r,
                        col: startCol
                    });
                }
                word = "";
                startCol = -1;
            }
        }
    }

    // Extract Down Words & Match Clues
    for (let c = 0; c < size; c++) {
        let word = "";
        let startRow = -1;
        for (let r = 0; r <= size; r++) {
            if (r < size && grid[r][c] !== '.') {
                if (startRow === -1) startRow = r;
                word += grid[r][c];
            } else {
                if (word.length >= 2) {
                    const aiClueStr = json.downClues.find((s: string) => s.startsWith(`${c}|`));
                    let text = aiClueStr ? aiClueStr.split('|')[1] : `Hint for ${word}`;

                    clues.push({
                        number: gridNumbers[startRow][c]!,
                        direction: 'down',
                        text: text,
                        answer: word,
                        row: startRow,
                        col: c
                    });
                }
                word = "";
                startRow = -1;
            }
        }
    }

    return {
      title: json.title || "Daily Crossword",
      theme: topic,
      gridSize: size,
      grid,
      clues
    };

  } catch (error) {
    console.error("Failed to generate puzzle:", error);
    throw error;
  }
};

export const getHintForCell = async (clue: string, currentAnswerPattern: string): Promise<string> => {
    // Very simple hint generation
    const prompt = `Clue: "${clue}". Pattern: "${currentAnswerPattern}". One short hint.`;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: prompt,
        config: { thinkingConfig: { thinkingBudget: 0 } }
    });
    return response.text || "No hint available.";
}

