                        <span className="font-bold">Music</span>
                    </button>
                    {savedGameExists && (
                         <button onClick={() => { setGameState(JSON.parse(localStorage.getItem('popcross_save_v2')!)); }} className="col-span-2 p-4 bg-gradient-to-r from-slate-800 to-slate-900 border border-fuchsia-500/30 rounded-xl flex justify-center items-center gap-3 hover:border-fuchsia-500 transition-colors">
                            <span className="font-bold text-fuchsia-300">Resume Last Session</span>
                        </button>
