import { GoogleGenAI, Type, Schema } from "@google/genai";
import { PuzzleData, Clue, Difficulty, Region } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const getGridSize = (difficulty: Difficulty): number => {
  switch (difficulty) {
    case 'Easy': return 6;      
    case 'Medium': return 8;    
    case 'Hard': return 10;     
    case 'Expert': return 12;   
    default: return 6;
  }
};

const getPuzzleSchema = (size: number): Schema => {
  return {
    type: Type.OBJECT,
    properties: {
      title: { type: Type.STRING, description: "A witty title" },
      rows: {
        type: Type.ARRAY,
        description: `${size} strings, each ${size} chars. '.' for black squares. Uppercase letters.`,
        items: { type: Type.STRING }
      },
      acrossClues: {
        type: Type.ARRAY,
        description: "Strings like 'RowIndex|ClueText'",
        items: { type: Type.STRING }
      },
      downClues: {
        type: Type.ARRAY,
        description: "Strings like 'ColIndex|ClueText'",
        items: { type: Type.STRING }
      },
      wordsToCheck: {
        type: Type.ARRAY,
        description: "A complete list of every single correct word (answer) placed in the grid. Used for spelling validation.",
        items: { type: Type.STRING }
      }
    },
    required: ["title", "rows", "acrossClues", "downClues", "wordsToCheck"]
  };
};

export const generatePuzzle = async (topic: string, difficulty: Difficulty, region: Region): Promise<PuzzleData> => {
  const modelId = "gemini-3-flash-preview";
  const size = getGridSize(difficulty);
  const schema = getPuzzleSchema(size);

  const prompt = `
    Generate a ${size}x${size} crossword grid for topic: "${topic}".

    Instructions:
    1. Grid Style: "Blocked". Use black squares ('.') to separate words.
    2. Density: High. Try to fit as many words as possible into the grid.
    3. Symmetry: Not required.
    4. SPELLING & VALIDATION: 
       - Ensure EVERY word formed in the grid (Across and Down) is a valid word or proper noun.
       - Check all intersections strictly. 
       - Do not create non-words to make the grid fit.
       - List ALL answer words in the 'wordsToCheck' output field. This list MUST be exhaustive; any word found in the grid not in this list will cause a validation failure.

    Content Strategy:
    - Topic: ${topic} (${region} context).
    - Difficulty: ${difficulty}.
    ${difficulty === 'Hard' || difficulty === 'Expert' 
      ? "- Use less common words and more challenging clues." 
      : "- Use common words and direct clues."}

    Output Requirements:
    - 'rows': Array of ${size} strings representing the grid rows.
    - 'acrossClues': Array of strings formatted as "RowIndex|Clue Text".
    - 'downClues': Array of strings formatted as "ColIndex|Clue Text".
    - 'wordsToCheck': List of all valid words used in the grid.
  `;

  let attempts = 0;
  const maxAttempts = 5;

  while (attempts < maxAttempts) {
    try {
        const response = await ai.models.generateContent({
        model: modelId,
        contents: prompt,
        config: {
            responseMimeType: "application/json",
            responseSchema: schema,
            thinkingConfig: { thinkingBudget: 12000 } // Increased budget for better quality and validation
        }
        });

        const json = JSON.parse(response.text || "{}");

        if (!json.rows || json.rows.length !== size) {
        throw new Error("Invalid puzzle generated");
        }

        // Convert string rows to 2D array
        const grid: string[][] = json.rows.map((row: string) => row.toUpperCase().split('').slice(0, size));
        const clues: Clue[] = [];

        let clueNumber = 1;
        const gridNumbers: (number | null)[][] = Array(size).fill(null).map(() => Array(size).fill(null));

        // Logic to assign numbers to the grid
        for (let r = 0; r < size; r++) {
            for (let c = 0; c < size; c++) {
                if (grid[r][c] === '.') continue;

                const isAcrossStart = (c === 0 || grid[r][c-1] === '.') && (c + 1 < size && grid[r][c+1] !== '.');
                const isDownStart = (r === 0 || grid[r-1][c] === '.') && (r + 1 < size && grid[r+1][c] !== '.');

                if (isAcrossStart || isDownStart) {
                    gridNumbers[r][c] = clueNumber++;
                }
            }
        }

        // Extract Across Words & Match Clues
        const extractedWords: string[] = [];

        for (let r = 0; r < size; r++) {
            let word = "";
            let startCol = -1;
            for (let c = 0; c <= size; c++) {
                if (c < size && grid[r][c] !== '.') {
                    if (startCol === -1) startCol = c;
                    word += grid[r][c];
                } else {
                    if (word.length >= 2) {
                        extractedWords.push(word);
                        // Fuzzy match the clue from AI response
                        const aiClueStr = json.acrossClues.find((s: string) => s.startsWith(`${r}|`));
                        let text = aiClueStr ? aiClueStr.split('|')[1] : `Hint for ${word}`;

                        clues.push({
                            number: gridNumbers[r][startCol]!,
                            direction: 'across',
                            text: text,
                            answer: word,
                            row: r,
                            col: startCol
                        });
                    }
                    word = "";
                    startCol = -1;
                }
            }
        }

        // Extract Down Words & Match Clues
        for (let c = 0; c < size; c++) {
            let word = "";
            let startRow = -1;
            for (let r = 0; r <= size; r++) {
                if (r < size && grid[r][c] !== '.') {
                    if (startRow === -1) startRow = r;
                    word += grid[r][c];
                } else {
                    if (word.length >= 2) {
                        extractedWords.push(word);
                        const aiClueStr = json.downClues.find((s: string) => s.startsWith(`${c}|`));
                        let text = aiClueStr ? aiClueStr.split('|')[1] : `Hint for ${word}`;

                        clues.push({
                            number: gridNumbers[startRow][c]!,
                            direction: 'down',
                            text: text,
                            answer: word,
                            row: startRow,
                            col: c
                        });
                    }
                    word = "";
                    startRow = -1;
                }
            }
        }

        // Validation Step
        // We trust the LLM's 'wordsToCheck' list as the source of truth for "Correct Spelling".
        // If the grid contains a word that is NOT in that list, it likely means the grid has a typo/hallucination intersection.
        if (json.wordsToCheck && Array.isArray(json.wordsToCheck)) {
            const validSet = new Set(json.wordsToCheck.map((w: string) => w.toUpperCase().trim()));
            const invalidWords = extractedWords.filter(w => !validSet.has(w));

            if (invalidWords.length > 0) {
                console.warn(`Validation Failed: Grid contains words not in intended list (likely typos or list mismatch): ${invalidWords.join(', ')}. Retrying...`);
                attempts++;
                continue; // Retry
            }
        }

        return {
        title: json.title || "Daily Crossword",
        theme: topic,
        gridSize: size,
        grid,
        clues
        };

    } catch (error) {
        console.error("Failed to generate puzzle attempt " + (attempts+1), error);
        attempts++;
        if (attempts >= maxAttempts) throw error;
    }
  }
  throw new Error("Unable to generate a valid puzzle. Please try again.");
};

