                      <span>{d}</span>
                      <span className={`text-[10px] px-1.5 py-0.5 rounded ${gameState.settings.difficulty === d ? 'bg-black/10 text-black' : 'bg-slate-800 text-slate-400'}`}>
                        {POINTS_BY_DIFFICULTY[d]}pts
