                            ${gameState.settings.region === r.id ? 'bg-cyan-500 text-white border-cyan-500 shadow-[0_0_15px_rgba(6,182,212,0.5)]' : 'bg-transparent text-slate-500 border-slate-800 hover:border-slate-600'}`}
