import { Badge, GameStats, CellData } from './types';

// Constants for initial values and difficulty levels
const INITIAL_STATS: GameStats = {
  score: 0,
  xp: 0,
  level: 1,
  xpToNextLevel: 100,
  gamesPlayed: 0,
  gamesCompleted: 0,
  hintsUsed: 0,
  longestStreak: 0,
  currentStreak: 0,
  badges: [],
};

const INITIAL_SETTINGS = {
    useAutoCheck: true,
};

const POINTS_BY_DIFFICULTY: { [key: string]: number } = {
  easy: 10,
  medium: 20,
  hard: 30,
  expert: 40,
  daily: 50,
};

const PENALTY_CORRECT_CHAR: number = 0;
const PENALTY_INCORRECT_CHAR: number = -1;
const PENALTY_HINT_USED: number = -10;

const badgesData = {
    beginner: {
        threshold: 1,
        title: 'Beginner',
        description: 'Completed your first puzzle!',
        icon: '🥇',
    },
    bronze: {
        threshold: 5,
        title: 'Bronze',
        description: 'Completed 5 puzzles.',
        icon: '🥉',
    },
    silver: {
        threshold: 10,
        title: 'Silver',
        description: 'Completed 10 puzzles.',
        icon: '🥈',
    },
    gold: {
        threshold: 20,
        title: 'Gold',
        description: 'Completed 20 puzzles.',
        icon: '🌟',
    },
    daily: {
        threshold: 1,
        title: 'Daily',
        description: 'Completed a Daily Puzzle!',
        icon: '📅',
    },
};

const checkBadges = (currentStats: GameStats) => {
    let newBadges: Badge[] = [];
    if (currentStats.gamesCompleted >= badgesData.beginner.threshold && !currentStats.badges.includes(badgesData.beginner.title)) {
