import { PuzzleData, GameState } from '../types';

const DAILY_KEY = 'popcross_db_daily';
const WORD_BANK_PREFIX = 'popcross_words_';

export interface DailyCache {
    date: string;
    puzzle: PuzzleData;
}

export interface WordItem {
    answer: string;
    clue: string;
}

// --- Word Bank Database ---

export const getWordBank = (topic: string, difficulty: string): WordItem[] => {
    try {
        const key = `${WORD_BANK_PREFIX}${topic}_${difficulty}`;
        const stored = localStorage.getItem(key);
        return stored ? JSON.parse(stored) : [];
    } catch (e) {
        console.error("WordBank Read Error", e);
        return [];
    }
};

export const saveToWordBank = (topic: string, difficulty: string, newWords: WordItem[]) => {
    try {
        const key = `${WORD_BANK_PREFIX}${topic}_${difficulty}`;
        const existing = getWordBank(topic, difficulty);

        // Merge and Deduplicate
        const map = new Map<string, WordItem>();
        existing.forEach(w => map.set(w.answer, w));
        newWords.forEach(w => map.set(w.answer, w));

        const merged = Array.from(map.values());

        // Limit size to prevent localStorage overflow (keep last 500 words per topic for deep offline play)
        const trimmed = merged.slice(0, 500);

        localStorage.setItem(key, JSON.stringify(trimmed));
    } catch (e) {
        console.error("WordBank Write Error", e);
    }
};

export const getWordBankStats = (): Record<string, number> => {
    const stats: Record<string, number> = {};
    try {
        for (let i = 0; i < localStorage.length; i++) {
            const key = localStorage.key(i);
            if (key && key.startsWith(WORD_BANK_PREFIX)) {
                // Key format: popcross_words_Movies_Medium
                const parts = key.replace(WORD_BANK_PREFIX, '').split('_');
                const topic = parts[0];
                const count = JSON.parse(localStorage.getItem(key) || '[]').length;
                stats[topic] = (stats[topic] || 0) + count;
            }
        }
    } catch (e) {
        console.error("Stats Read Error", e);
    }
    return stats;
};

// --- Daily Puzzle Database ---

export const getDailyPuzzleFromDb = (): PuzzleData | null => {
    try {
        const stored = localStorage.getItem(DAILY_KEY);
        if (!stored) return null;

        const parsed: DailyCache = JSON.parse(stored);
        const today = new Date().toISOString().split('T')[0];

        // Return only if it matches today's date
        if (parsed.date === today) {
            return parsed.puzzle;
        }

        // Expire old cache
        localStorage.removeItem(DAILY_KEY);
        return null;
    } catch (e) {
        console.error("DB Read Error", e);
        return null;
    }
};

export const saveDailyPuzzleToDb = (puzzle: PuzzleData) => {
    try {
        const today = new Date().toISOString().split('T')[0];
        const cache: DailyCache = { date: today, puzzle };
        localStorage.setItem(DAILY_KEY, JSON.stringify(cache));
    } catch (e) {
        console.error("DB Write Error", e);
    }
};

// --- General Persistence ---

export const saveGameState = (state: GameState) => {
    localStorage.setItem('popcross_save_v2', JSON.stringify(state));
};

export const loadGameState = (): GameState | null => {
    const saved = localStorage.getItem('popcross_save_v2');
    return saved ? JSON.parse(saved) : null;
};

export const clearGameState = () => {
    localStorage.removeItem('popcross_save_v2');
};

import { GoogleGenAI, Schema, Type } from "@google/genai";
import { saveToWordBank, WordItem } from "./storageService";
import { Difficulty } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// We use the flash model with search tools for efficient scraping
const MODEL_ID = "gemini-3-flash-preview";

export const scrapeCategoryWords = async (
    category: string, 
    onProgress?: (msg: string) => void
): Promise<number> => {

    // We scrape for 'Medium' difficulty as a baseline, as it fits most grids.
    // The game logic can filter these for Easy/Hard based on length later.
    const TARGET_DIFFICULTY: Difficulty = 'Medium'; 
    const BATCH_SIZE = 50;

    onProgress?.(`Initializing web scraper for ${category}...`);

    const prompt = `
        Task: Scrape the web for a crossword puzzle database about "${category}".

        1. Search for authoritative websites, wikis, and fan pages related to ${category}.
        2. Extract distinct terminology, names, titles, slang, and trivia answers.
        3. Create exactly ${BATCH_SIZE} unique pairings of (Answer, Clue).

        Constraints:
        - Answers must be single words or merged phrases (e.g., "STARWARS", "BRADPITT").
        - Uppercase answers only.
        - No special characters.
        - Length: 3 to 12 letters.
        - Clues must be short (under 6 words).
        - STRICTLY RELEVANT to ${category}.

        Output JSON: [{ "answer": "WORD", "clue": "Hint" }, ...]
    `;

    const schema: Schema = {
        type: Type.ARRAY,
        items: {
            type: Type.OBJECT,
            properties: {
                answer: { type: Type.STRING },
                clue: { type: Type.STRING }
            },
            required: ["answer", "clue"]
        }
    };

    try {
        onProgress?.(`Searching authoritative sources for ${category}...`);

        // We use googleSearch tool to ground the generation in real web data
        const response = await ai.models.generateContent({
            model: MODEL_ID,
            contents: prompt,
            config: {
                tools: [{ googleSearch: {} }],
                responseMimeType: "application/json",
                responseSchema: schema,
                temperature: 0.5 // Low temp for factual/accurate data
            }
        });

        onProgress?.("Parsing and sanitizing data...");

        let cleanText = response.text || "[]";
        cleanText = cleanText.replace(/```json/g, '').replace(/```/g, '').trim();

        let data: any[] = [];
        try {
            data = JSON.parse(cleanText);
        } catch (e) {
            console.error("JSON Parse Error", e);
            throw new Error("Failed to parse scraped data.");
        }

        if (!Array.isArray(data)) throw new Error("Invalid format returned.");

        const validWords: WordItem[] = data
            .filter(i => i.answer && i.clue)
            .map(i => ({
                answer: i.answer.trim().toUpperCase().replace(/[^A-Z]/g, ''),
                clue: i.clue.trim()
            }))
            .filter(i => i.answer.length >= 3 && i.answer.length <= 15);

        // Save to Local Storage
        onProgress?.(`Saving ${validWords.length} new words to local database...`);
        saveToWordBank(category, TARGET_DIFFICULTY, validWords);

        // Also save to Hard/Easy buckets to distribute the wealth
        // (In a real app, we might split them based on complexity, but copying works for cache)
        saveToWordBank(category, 'Hard', validWords); 
        saveToWordBank(category, 'Easy', validWords);

        return validWords.length;

    } catch (e) {
        console.error("Scraping Failed", e);
        throw e;
    }
};

