                    </button>
                </div>
            </div>
          </div>

          {/* Scraper / Content Manager */}
          <div className="glass-panel p-4 rounded-xl border border-slate-800">
             <div className="flex items-center gap-2 mb-3">
                <Database size={18} className="text-emerald-400" />
