            {gameState.view === 'categories' && <CategoriesView />}
            {gameState.view === 'profile' && <ProfileView />}

            {gameState.view === 'game' && (
                <div className="h-full flex flex-col animate-[fade-in_0.3s_ease-out]">
                    {gameState.status === 'generating' ? (
