import { PuzzleData, GameState } from '../types';

const DAILY_KEY = 'popcross_db_daily';
const WORD_BANK_PREFIX = 'popcross_words_';
const HISTORY_KEY = 'popcross_custom_history';

export interface DailyCache {
    date: string;
    puzzle: PuzzleData;
}

export interface WordItem {
    answer: string;
    clue: string;
}

export interface HistoryItem {
    topic: string;
    answer: string;
    clue: string;
    timestamp: number;
}

// --- Word Bank Database ---

export const getWordBank = (topic: string, difficulty: string): WordItem[] => {
    try {
        const key = `${WORD_BANK_PREFIX}${topic}_${difficulty}`;
        const stored = localStorage.getItem(key);
        return stored ? JSON.parse(stored) : [];
    } catch (e) {
        console.error("WordBank Read Error", e);
        return [];
    }
};

export const saveToWordBank = (topic: string, difficulty: string, newWords: WordItem[]) => {
    try {
        const key = `${WORD_BANK_PREFIX}${topic}_${difficulty}`;
        const existing = getWordBank(topic, difficulty);

        // Merge and Deduplicate
        const map = new Map<string, WordItem>();
        existing.forEach(w => map.set(w.answer, w));
        newWords.forEach(w => map.set(w.answer, w));

        const merged = Array.from(map.values());

        // Limit size to prevent localStorage overflow (keep last 500 words per topic for deep offline play)
        // Fix: Use slice with negative index to keep the MOST RECENT additions (tail of the array)
        // existing items are at the start, new items are appended at the end.
        const trimmed = merged.length > 500 ? merged.slice(-500) : merged;

        localStorage.setItem(key, JSON.stringify(trimmed));
    } catch (e) {
        console.error("WordBank Write Error", e);
    }
};

export const getCustomHistory = (): HistoryItem[] => {
    try {
        const stored = localStorage.getItem(HISTORY_KEY);
        return stored ? JSON.parse(stored) : [];
    } catch (e) {
        return [];
    }
};

export const addCustomWord = (topic: string, word: string, clue: string) => {
    const item: WordItem = { answer: word.toUpperCase(), clue };

    // We add the word to ALL difficulty buckets. 
    // The game engine filters by length at runtime, so it will appear in the correct difficulty automatically.
    const difficulties = ['Easy', 'Medium', 'Hard', 'Expert'];
    difficulties.forEach(diff => {
        saveToWordBank(topic, diff, [item]);
    });

    // Save to History Log
    try {
        const history = getCustomHistory();
        const newEntry: HistoryItem = { 
            topic, 
            answer: word.toUpperCase(), 
            clue, 
            timestamp: Date.now() 
        };
        // Prepend new entry, keep last 10
        const updated = [newEntry, ...history].slice(0, 10);
        localStorage.setItem(HISTORY_KEY, JSON.stringify(updated));
    } catch (e) {
        console.error("History Save Error", e);
    }
};

export const deleteCustomWord = (topic: string, answer: string) => {
    const target = answer.toUpperCase();
    const difficulties = ['Easy', 'Medium', 'Hard', 'Expert'];

    // Remove from Word Banks
    difficulties.forEach(diff => {
        const key = `${WORD_BANK_PREFIX}${topic}_${diff}`;
        const stored = localStorage.getItem(key);
        if (stored) {
            const existing: WordItem[] = JSON.parse(stored);
            const filtered = existing.filter(w => w.answer !== target);
            // Only write if changed
            if (filtered.length !== existing.length) {
                localStorage.setItem(key, JSON.stringify(filtered));
            }
        }
    });

    // Remove from History
    try {
        const history = getCustomHistory();
        const newHistory = history.filter(h => !(h.topic === topic && h.answer === target));
        localStorage.setItem(HISTORY_KEY, JSON.stringify(newHistory));
    } catch (e) {
        console.error("History delete error", e);
    }
};

export const getWordBankStats = (): Record<string, number> => {
    const stats: Record<string, number> = {};
    try {
        for (let i = 0; i < localStorage.length; i++) {
            const key = localStorage.key(i);
            if (key && key.startsWith(WORD_BANK_PREFIX)) {
                // Key format: popcross_words_Movies_Medium
                const parts = key.replace(WORD_BANK_PREFIX, '').split('_');
                const topic = parts[0];

                // Get count for this specific difficulty bucket
                const count = JSON.parse(localStorage.getItem(key) || '[]').length;

                // We take the MAX count across difficulties to represent the "Words Cached" for the topic.
                // Since scraping saves identical lists to Easy/Med/Hard, Max avoids triple counting.
                // If the user only played Hard online, Max will correctly show that count.
                stats[topic] = Math.max((stats[topic] || 0), count);
            }
        }
    } catch (e) {
        console.error("Stats Read Error", e);
    }
    return stats;
};

// --- Daily Puzzle Database ---

export const getDailyPuzzleFromDb = (): PuzzleData | null => {
    try {
        const stored = localStorage.getItem(DAILY_KEY);
        if (!stored) return null;

        const parsed: DailyCache = JSON.parse(stored);
        const today = new Date().toISOString().split('T')[0];

        // Return only if it matches today's date
        if (parsed.date === today) {
            return parsed.puzzle;
        }

        // Expire old cache
        localStorage.removeItem(DAILY_KEY);
        return null;
    } catch (e) {
        console.error("DB Read Error", e);
        return null;
    }
};

export const saveDailyPuzzleToDb = (puzzle: PuzzleData) => {
    try {
        const today = new Date().toISOString().split('T')[0];
        const cache: DailyCache = { date: today, puzzle };
        localStorage.setItem(DAILY_KEY, JSON.stringify(cache));
    } catch (e) {
        console.error("DB Write Error", e);
    }
};

// --- General Persistence ---

export const saveGameState = (state: GameState) => {
    localStorage.setItem('popcross_save_v2', JSON.stringify(state));
};

export const loadGameState = (): GameState | null => {
    const saved = localStorage.getItem('popcross_save_v2');
    return saved ? JSON.parse(saved) : null;
};

export const clearGameState = () => {
    localStorage.removeItem('popcross_save_v2');
};

