      setIsScraping(categoryId);
      setScrapeProgress("Starting...");

      try {
          await scrapeCategoryWords(categoryId, (msg) => setScrapeProgress(msg));
          // Refresh stats
          setWordBankStats(getWordBankStats());
          setScrapeProgress("Done!");
          setTimeout(() => {
