              setScrapeProgress("");
          }, 1500);
      } catch (e: any) {
          if (e.message === 'QUOTA_EXCEEDED') {
              setApiStatus('quota-exceeded');
          }
          setScrapeProgress("Failed.");
          setTimeout(() => {
              setIsScraping(null);
              setScrapeProgress("");
